INSERT INTO `berita` (`id`, `judul`, `slug`, `kategori`, `konten`, `ringkasan`, `gambar`, `penulis`, `sumber`, `views`, `status`, `featured`, `created_at`, `updated_at`, `published_at`) VALUES
(1, 'Orasi Soal Deforestasi Antarkan Mahasiswa UT Jadi Juara Green Policing 2026', 'orasi-soal-deforestasi-antarkan-mahasiswa-ut-jadi-juara-green-policing-2026', 'berita', '<p>Suasana Atrium Mal SKA Pekanbaru, Minggu (15/2/2026), terasa semarak. Mahasiswa Universitas Terbuka (UT) berhasil meraih juara dalam ajang Green Policing 2026 dengan orasi mengesankan tentang deforestasi. Kompetisi yang diikuti oleh puluhan perguruan tinggi se-Indonesia ini menjadi ajang unjuk kemampuan mahasiswa dalam menyuarakan isu lingkungan.</p><p>Dalam orasinya, mahasiswa UT menyampaikan data dan fakta tentang deforestasi di Indonesia serta solusi inovatif untuk mengatasinya. Penampilan yang penuh semangat dan didukung data akurat berhasil memukau dewan juri.</p><p>Kemenangan ini membuktikan bahwa mahasiswa UT tidak hanya unggul dalam akademik tetapi juga memiliki kepedulian tinggi terhadap isu lingkungan. Green Policing 2026 sendiri merupakan ajang tahunan yang bertujuan mendorong partisipasi mahasiswa dalam pelestarian lingkungan.</p>', 'Mahasiswa Universitas Terbuka berhasil meraih juara dalam ajang Green Policing 2026 dengan orasi tentang deforestasi yang memukau dewan juri.', 'green-policing.jpg', 'Humas UT', NULL, 1258, 'publish', 1, '2026-02-21 08:00:00', '2026-06-03 09:15:37', '2026-02-21 08:00:00'),
(4, 'Pengumuman Pendaftaran Calon Tutor Tutorial Online Semester 2025/2026 Genap', 'pengumuman-pendaftaran-calon-tutor-tutorial-online-semester-2025-2026-genap', 'pengumuman', '<p>Universitas Terbuka membuka kesempatan bagi para profesional dan akademisi untuk bergabung sebagai tutor tutorial online untuk semester 2025/2026 Genap. Pendaftaran dibuka mulai tanggal 9 Februari 2026.</p><p>Kualifikasi yang dibutuhkan: pendidikan minimal S2 sesuai bidang yang diminati, memiliki koneksi internet yang stabil, dan mampu menggunakan platform pembelajaran online. Pengalaman mengajar akan menjadi nilai tambah.</p><p>Pendaftaran dilakukan secara online melalui laman karir.ut.ac.id. Berkas yang perlu disiapkan: CV terbaru, ijazah dan transkrip, serta surat rekomendasi (jika ada).</p>', 'Pendaftaran calon tutor online UT semester genap telah dibuka. Segera daftarkan diri Anda.', 'pendaftaran-tutor.jpg', 'Biro SDM', NULL, 1874, 'publish', 0, '2026-02-09 08:00:00', '2026-06-03 09:16:30', '2026-02-09 08:00:00'),
(5, 'Perpanjangan Jadwal Pendaftaran Mahasiswa Baru Jalur RPL Program Sarjana dan Diploma Semester 2025/2026 Genap', 'perpanjangan-jadwal-pendaftaran-mahasiswa-baru-jalur-rpl-program-sarjana-dan-diploma-semester-2025-2026-genap', 'pengumuman', '<p>Universitas Terbuka mengumumkan perpanjangan jadwal pendaftaran mahasiswa baru jalur Rekognisi Pembelajaran Lampau (RPL) untuk program Sarjana dan Diploma semester 2025/2026 Genap. Pendaftaran diperpanjang hingga 7 Desember 2025.</p><p>Jalur RPL memberikan kesempatan bagi calon mahasiswa untuk mendapatkan pengakuan atas pengalaman belajar sebelumnya, baik dari pendidikan formal, nonformal, informal, maupun pengalaman kerja. Hal ini dapat memperpendek masa studi.</p><p>Informasi lengkap mengenai persyaratan dan tata cara pendaftaran dapat diakses melalui laman rpl.ut.ac.id atau menghubungi pusat layanan UT terdekat.</p>', 'Pendaftaran mahasiswa baru jalur RPL UT diperpanjang hingga 7 Desember 2025. Manfaatkan kesempatan ini.', 'rpl-perpanjangan.jpg', 'PMB UT', NULL, 1453, 'publish', 0, '2025-12-07 09:00:00', '2026-06-03 09:15:05', '2025-12-07 09:00:00'),
(6, 'Pendidikan Tidak Boleh Tumbang di Tengah Bencana: Komitmen Universitas Terbuka untuk Mahasiswa Terdampak', 'pendidikan-tidak-boleh-tumbang-di-tengah-bencana-komitmen-universitas-terbuka-untuk-mahasiswa-terdampak', 'artikel', '<h1><strong>Pendidikan Tidak Boleh Tumbang di Tengah Bencana: Komitmen Universitas Terbuka untuk Mahasiswa Terdampak</strong></h1>\r\n\r\n<p><strong>Tapanuli Tengah/Jakarta</strong>&nbsp;&ndash; Di tengah hiruk-pikuk penanganan bencana banjir bandang dan longsor yang melanda sejumlah wilayah di Provinsi Aceh, Sumatera Utara, dan Sumatera Barat pada akhir tahun 2025 lalu, muncul kisah-kisah heroik tentang keteguhan para mahasiswa untuk tetap menjalankan kewajiban akademiknya. Salah satu kisah yang paling menyita perhatian adalah perjuangan Eska Laurensia Sinabutar, seorang mahasiswi Universitas Terbuka (UT) Medan&nbsp;.</p>\r\n\r\n<h2>Berjalan 4 Jam Demi Sinyal</h2>\r\n\r\n<p>Eska, mahasiswi semester 9 Program Studi PGSD, harus berjuang ekstra keras di tengah kondisi yang serba terbatas. Banjir bandang dan longsor yang melanda Kecamatan Tukka, Tapanuli Tengah, membuat akses listrik padam total dan jaringan telekomunikasi terputus. Padahal, tugas akhir kuliahnya sudah mendekati batas waktu pengumpulan&nbsp;.</p>\r\n\r\n<p>Dengan tas ransel berisi laptop, charger, dan dokumen kuliah yang ikut basah, Eska nekat berjalan kaki keluar dari kampungnya. Medan yang dilewati tidak mudah; jalanan masih tertutup lumpur dan akses banyak yang terputus. &quot;Saya berjalan kurang lebih empat jam. Kadang harus berhenti karena capek, kadang karena jalannya rusak. Tapi saya harus terus maju supaya bisa kirim tugas,&quot; ujarnya&nbsp;.</p>\r\n\r\n<p>Harapan datang ketika ia tiba di GOR Pandan, lokasi yang dijadikan Pusat Informasi dan Media Center oleh Kementerian Komunikasi dan Digital (Kemkomdigi). Fasilitas darurat dengan akses internet dan listrik itu menjadi &quot;ruang harapan&quot; baginya. &quot;Begitu lihat ada Wi-Fi dan listrik, saya langsung menangis pelan. Rasanya seperti nemu harapan,&quot; kenang Eska yang akhirnya bisa mengirimkan tugas akhirnya dengan lancar&nbsp;. Kisah Eska ini menjadi simbol nyata bahwa pendidikan harus tetap berjalan, bahkan dari tengah bencana sekalipun.</p>\r\n\r\n<h2>UT Hadir dengan Kebijakan Afirmatif</h2>\r\n\r\n<p>Kisah seperti Eska hanyalah satu dari ribuan mahasiswa UT lainnya yang terdampak bencana hidrometeorologi di wilayah Sumatera. Menyadari hal tersebut, Universitas Terbuka sebagai institusi pendidikan tinggi tidak tinggal diam. Rektor UT, Prof. Dr. Ali Muktiyanto, S.E.,&nbsp;<a href=\"https://m.si/\" target=\"_blank\">M.Si</a>.,&nbsp;menegaskan bahwa bencana alam tidak boleh menjadi alasan terhentinya pendidikan&nbsp;.</p>\r\n\r\n<p>&quot;Universitas Terbuka hadir untuk memastikan mahasiswa tetap dapat melanjutkan studi meskipun berada dalam situasi sulit. Pembebasan UKT ini adalah bentuk empati, kepedulian, dan komitmen kami agar mahasiswa tidak kehilangan masa depannya akibat bencana,&quot; ujar Prof. Ali&nbsp;.</p>\r\n\r\n<p>Sebagai wujud nyata kepedulian tersebut, UT meluncurkan kebijakan strategis melalui program&nbsp;<strong>UT Peduli</strong>. Kebijakan yang diberlakukan pada Semester Ganjil Tahun Akademik 2025/2026 ini memberikan&nbsp;<strong>pembebasan Uang Kuliah Tunggal (UKT)</strong>&nbsp;bagi mahasiswa terdampak bencana. Bantuan diberikan dalam bentuk beasiswa pembebasan UKT selama satu hingga dua semester, yang disesuaikan dengan tingkat keparahan dampak bencana yang dialami mahasiswa&nbsp;.</p>\r\n\r\n<p>Hasilnya, sebanyak&nbsp;<strong>2.020 mahasiswa</strong>&nbsp;UT di wilayah terdampak, seperti Kabupaten Tapanuli Tengah, Kota Sibolga, Kabupaten Aceh Tamiang, dan Kota Medan, tercatat menerima manfaat dari kebijakan ini&nbsp;.</p>\r\n\r\n<h2>Lebih dari Sekadar UKT</h2>\r\n\r\n<p>Program UT Peduli tidak hanya berhenti pada pembebasan biaya kuliah. UT juga menyalurkan bantuan kemanusiaan berupa logistik kepada mahasiswa dan masyarakat di wilayah terdampak&nbsp;. Selain itu, UT mengembangkan program&nbsp;<strong>Pengabdian kepada Masyarakat (PkM)</strong>&nbsp;yang difokuskan pada pemulihan kondisi sosial masyarakat pascabencana&nbsp;.</p>\r\n\r\n<p>Solidaritas juga datang dari sesama mahasiswa. Organisasi Mahasiswa (Ormawa) UT Surabaya, misalnya, menggelar aksi penggalangan dana bagi korban bencana di Sumatera sebagai wujud kepedulian dan pembelajaran nilai-nilai kemanusiaan&nbsp;.</p>\r\n\r\n<p>Dalam pelaksanaannya, UT Daerah secara aktif berkoordinasi dengan pemerintah daerah setempat untuk memastikan bantuan tersalurkan secara tepat sasaran. Sinergi lintas sektor ini menjadi kunci dalam mendukung upaya penanganan bencana dan pemulihan pascabencana&nbsp;.</p>\r\n\r\n<p>Langkah komprehensif ini sejalan dengan komitmen Universitas Terbuka dalam mendukung Tujuan Pembangunan Berkelanjutan (Sustainable Development Goals/SDGs), khususnya&nbsp;<strong>SDG 4</strong>&nbsp;tentang Pendidikan Berkualitas,&nbsp;<strong>SDG 10</strong>&nbsp;tentang Pengurangan Ketimpangan, serta&nbsp;<strong>SDG 17</strong>&nbsp;tentang Kemitraan untuk Mencapai Tujuan&nbsp;.</p>\r\n\r\n<p>Di tengah bencana yang menguji ketahanan, Universitas Terbuka menegaskan perannya bukan hanya sebagai institusi akademik, tetapi juga sebagai mitra yang mendampingi mahasiswa dan masyarakat untuk tetap melangkah, pulih, dan bertahan. Pendidikan tidak boleh tumbang, dan UT hadir untuk memastikan hal itu&nbsp;</p>\r\n', 'Universitas Terbuka berkomitmen memberikan dukungan penuh bagi mahasiswa terdampak bencana alam agar tetap bisa melanjutkan pendidikan.', 'bencana.jpg', 'Redaksi', NULL, 2110, 'publish', 1, '2025-12-31 11:00:00', '2026-05-18 15:08:36', '2025-12-31 11:00:00'),
(7, 'Kuliah, Kerja, dan Mewujudkan Mimpi — Semua Bisa Berjalan Bersamaan di Kampus ini', 'kuliah-kerja-dan-mewujudkan-mimpi-semuabisa-berjalan-bersamaan-di-kampus-ini', 'artikel', '<p>Banyak orang berpikir bahwa kuliah dan bekerja adalah dua hal yang sulit dijalankan bersamaan. Namun, Universitas Terbuka membuktikan bahwa keduanya bisa berjalan beriringan. Dengan sistem pembelajaran jarak jauh yang fleksibel, mahasiswa dapat mengatur waktu belajar sesuai dengan kesibukan mereka.</p><p>Andi (28), seorang karyawan swasta sekaligus mahasiswa UT, berbagi pengalamannya: \"Saya bisa bekerja dari pagi hingga sore, lalu belajar di malam hari. Tugas-tugas bisa dikerjakan secara online. Yang terpenting adalah manajemen waktu dan konsistensi.\"</p><p>UT menyediakan berbagai fasilitas pendukung seperti bahan ajar digital, tutorial online, dan perpustakaan digital yang dapat diakses kapan saja. Hal ini memudahkan mahasiswa untuk tetap produktif di tempat kerja sambil menyelesaikan studi.</p>', 'Kisah inspiratif mahasiswa UT yang berhasil menjalankan kuliah dan pekerjaan secara bersamaan dengan sistem pembelajaran fleksibel.', 'kuliah-kerja.jpg', 'Tim Redaksi', NULL, 3205, 'publish', 0, '2025-11-07 10:00:00', '2026-06-03 09:16:06', '2025-11-07 10:00:00'),
(8, 'Rahasia Sukses UT Kelola 760 Ribu Mahasiswa Daring, Undip Datang \"Berguru\" Langsung', 'rahasia-sukses-ut-kelola-760-ribu-mahasiswa-daring-undip-datang-berguru-langsung', 'berita', '<p>Keberhasilan Universitas Terbuka mengelola lebih dari 760 ribu mahasiswa secara daring menarik perhatian Universitas Diponegoro (Undip). Tim dari Undip melakukan kunjungan studi banding ke UT untuk mempelajari sistem pengelolaan pendidikan jarak jauh yang telah terbukti sukses.</p><p>\"Kami ingin belajar bagaimana UT mampu mengelola jumlah mahasiswa yang sangat besar dengan kualitas layanan yang tetap terjaga,\" ujar perwakilan tim Undip. Kunjungan ini difokuskan pada sistem pembelajaran daring, manajemen sumber daya, dan teknologi informasi yang digunakan.</p><p>UT dengan bangga berbagi pengalaman tentang platform pembelajaran, sistem evaluasi, dan strategi mempertahankan engagement mahasiswa. Kerjasama lanjutan direncanakan untuk pengembangan sistem serupa di Undip.</p>', 'Universitas Diponegoro melakukan studi banding ke UT untuk mempelajari sistem pengelolaan pendidikan jarak jauh dengan 760 ribu mahasiswa.', 'ut-undip.jpg', 'Humas UT', NULL, 1755, 'publish', 0, '2025-10-26 14:00:00', '2026-05-04 13:37:07', '2025-10-26 14:00:00'),
(9, 'Bukan Sekadar Medali: Mahasiswa UT Ciptakan Solusi Preventif Lawan Bullying di Level Internasional', 'bukan-sekadar-medali-mahasiswa-ut-ciptakan-solusi-preventif-lawan-bullying-di-level-internasional', 'berita', '<p>Di era ketika ruang digital menjadi bagian tak terpisahkan dari kehidupan, mahasiswa Universitas Terbuka menciptakan solusi inovatif untuk melawan bullying. Karya mereka tidak hanya meraih medali di ajang internasional, tetapi juga memberikan dampak nyata bagi masyarakat.</p><p>Solusi yang dikembangkan berupa aplikasi deteksi dini dan sistem pendukung bagi korban bullying. Aplikasi ini menggunakan kecerdasan buatan untuk mendeteksi potensi bullying dalam interaksi digital dan memberikan rekomendasi tindakan preventif.</p><p>\"Kami ingin menciptakan solusi yang tidak sekadar meraih penghargaan, tapi benar-benar membantu masyarakat,\" ujar ketua tim. Karya ini mendapatkan apresiasi luas dan sedang dalam proses pengembangan lebih lanjut untuk diimplementasikan di sekolah-sekolah.</p>', 'Mahasiswa UT ciptakan solusi berbasis AI untuk deteksi dini dan pencegahan bullying, meraih penghargaan internasional.', 'anti-bullying.jpg', 'Tim Riset', NULL, 2152, 'publish', 1, '2026-02-20 13:00:00', '2026-06-03 09:15:41', '2026-02-20 13:00:00'),
(10, 'Fakultas Industri Kreatif Hebat', 'fakultas-industri-kreatif-hebat', 'berita', '<p>Kabar gembira datang bagi para lulusan SMA/SMK/MA sederajat yang memiliki bakat di bidang seni dan desain.&nbsp;<strong>FIK Telkom University</strong>&nbsp;kembali membuka&nbsp;<strong>TelU Art Scholarship Program</strong>&nbsp;untuk tahun ajaran 2026/2027. Program beasiswa ini adalah kesempatan emas untuk berkuliah di salah satu universitas swasta terbaik di Indonesia dengan dukungan biaya pendidikan&nbsp;.</p>\r\n\r\n<p>Pendaftaran program ini telah dibuka sejak&nbsp;<strong>10 Desember 2025</strong>&nbsp;dan akan ditutup pada&nbsp;<strong>30 Januari 2026</strong>. Beasiswa ini menyasar calon mahasiswa yang ingin mengembangkan potensi di bidang desain, animasi, dan industri kreatif digital&nbsp;.</p>\r\n\r\n<p><strong>Program Studi yang Dapat Dipilih:</strong><br />\r\nFIK menawarkan beragam program studi (prodi) unggulan yang dapat dipilih oleh peserta, antara lain:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>S1 Desain Komunikasi Visual (DKV) - Tersedia di kampus Bandung, Jakarta, dan Purwokerto</p>\r\n	</li>\r\n	<li>\r\n	<p>S1 Desain Produk &amp; Inovasi</p>\r\n	</li>\r\n	<li>\r\n	<p>S1 Desain Interior - Tersedia di kampus Bandung dan Purwokerto</p>\r\n	</li>\r\n	<li>\r\n	<p>S1 Film &amp; Animasi</p>\r\n	</li>\r\n	<li>\r\n	<p>S1 Kriya (Fashion &amp; Textile Design)</p>\r\n	</li>\r\n	<li>\r\n	<p>S1 Creative Arts (Intermedia Visual Arts)&nbsp;</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Dua Kategori Beasiswa:</strong><br />\r\nTerdapat dua skema beasiswa yang ditawarkan, yaitu:</p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Beasiswa Unggulan:</strong>&nbsp;Memberikan pembebasan biaya pendidikan&nbsp;<strong>100%</strong>&nbsp;hingga lulus bagi pendaftar dengan portofolio dan prestasi terbaik.</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Beasiswa Pintar:</strong>&nbsp;Menawarkan potongan biaya pendidikan pada tahun pertama studi, berupa pembebasan 100% Biaya Partisipasi Pendidikan (UP3) dan/atau 100% Biaya Sumbangan Dana Pengembangan Pendidikan (SDP2)&nbsp;.</p>\r\n	</li>\r\n</ol>\r\n\r\n<p>Selain itu, Telkom University juga menawarkan program&nbsp;<strong>Fast Track</strong>&nbsp;yang memungkinkan mahasiswa menyelesaikan pendidikan S1 dan S2 hanya dalam waktu 5 tahun, sebuah nilai tambah untuk mendapatkan keunggulan kompetitif di dunia kerja&nbsp;.</p>\r\n\r\n<h2>Kolaborasi Nyata dengan Industri: Eksplorasi Denim</h2>\r\n\r\n<p>Tak hanya fokus pada penerimaan mahasiswa baru, FIK Telkom University juga aktif menjalin kolaborasi dengan dunia industri untuk memperkaya wawasan dan pengalaman mahasiswanya. Baru-baru ini, mahasiswa dari&nbsp;<strong>Departemen Fashion Design, FIK Telkom University</strong>, melakukan kunjungan industri ke PT. Garuda Mas Semesta (GAMATEX)&nbsp;.</p>\r\n\r\n<p>Dalam kunjungan tersebut, para mahasiswa diajak untuk mengeksplorasi dunia denim secara mendalam, mulai dari proses produksi, inovasi teknologi tekstil, hingga diskusi dengan para ahli. Kegiatan ini bukan sekadar tur pabrik, melainkan sebuah wadah pertukaran ide dan visi antara generasi muda dan praktisi industri. Kolaborasi ini diharapkan dapat menginspirasi para desainer masa depan untuk berpikir kritis, kreatif, dan berkelanjutan dalam memperkuat industri fesyen Indonesia di kancah global&nbsp;.</p>\r\n\r\n<h2>FIK Menjadi Bagian dari Ribuan Mahasiswa Baru Telkom University</h2>\r\n\r\n<p>Pada tahun akademik 2025/2026, FIK Telkom University menyumbangkan&nbsp;<strong>1.031 mahasiswa baru</strong>&nbsp;dari total 9.437 mahasiswa baru yang dikukuhkan. Jumlah ini menempatkan FIK sebagai fakultas dengan penyumbang mahasiswa baru terbesar kelima di Telkom University, menandakan tingginya minat calon mahasiswa terhadap bidang industri kreatif di kampus ini&nbsp;.</p>\r\n\r\n<p>Dengan berbagai program dan prestasinya, FIK Telkom University terus membuktikan komitmennya untuk menjadi salah satu fakultas terdepan dalam melahirkan talenta kreatif yang inovatif dan berdaya saing global.</p>\r\n', 'Fakultas Industri Kreatif (FIK) Telkom University terus menunjukkan geliatnya dalam mencetak talenta unggul di bidang seni dan desain. Berbagai agenda strategis, mulai dari pembukaan peluang beasiswa bagi calon mahasiswa hingga penguatan jejaring dengan industri kreatif, mewarnai langkah FIK di awal tahun 2026 ini.', 'b1754867359e85b48c3f48793529ba63.jpg', 'Administrator FIK', NULL, 15, 'publish', 1, '2026-02-25 10:51:46', '2026-06-03 09:16:36', '2026-02-25 10:51:46');
