(1, 'gaji staf', 'Gaji staf dibayarkan setiap tanggal 25 bulan berjalan.', 'penggajian,salary', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(2, 'prosedur cuti pegawai', 'Pegawai dapat mengajukan cuti melalui sistem HRIS.', 'cuti,izin', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(3, 'reimburse biaya', 'Form reimburse dapat diunduh di intranet kampus.', 'reimburse', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(4, 'slip gaji', 'Slip gaji dapat diakses melalui akun kepegawaian masing-masing.', 'slip,gaji', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(5, 'rekening payroll', 'Payroll ditransfer ke rekening utama yang terdaftar di HRIS.', 'bank,pembayaran', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(6, 'transkrip nilai', 'Transkrip nilai dapat diunduh melalui SIAKAD.', 'nilai,rekap,hasil', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(7, 'surat aktif kuliah', 'Surat aktif kuliah dapat diminta melalui bagian akademik fakultas.', 'status mahasiswa', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(8, 'pindah kelas', 'Mahasiswa harus mengisi form pindah kelas dan mendapat persetujuan prodi.', 'kelas,prodi,izin', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(9, 'jadwal kuliah', 'Jadwal kuliah tersedia di SIAKAD dan papan pengumuman fakultas.', 'kelas,jadwal', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(10, 'izin tidak hadir', 'Ajukan izin tidak hadir ke dosen pengampu melalui email resmi.', 'absen,izin', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(21, 'pinjam alat lab', 'Ajukan minimal H-2 melalui form peminjaman.', 'alat,laboratorium', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(22, 'jam operasional lab', 'Laboratorium buka Senin-Jumat pukul 08.00 - 16.00.', 'buka,operasional', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(23, 'safety induction', 'Mahasiswa wajib mengikuti safety induction sebelum praktik.', 'safety,lab', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(24, 'daftar alat', 'Daftar alat tersedia di website laboratorium.', 'alat,peralatan', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(25, 'bimbingan praktikum', 'Jadwal bimbingan tersedia di papan pengumuman lab.', 'asisten,bimbingan', 'general', 0, NULL, '2025-06-12 15:42:11', '2025-06-12 01:42:11'),
(31, 'Beasiswa', 'Telkom University menyediakan berbagai skema beasiswa internal untuk mendukung mahasiswa berprestasi serta mereka yang membutuhkan bantuan finansial selama masa studi. Beasiswa ini merupakan bentuk komitmen kampus dalam menciptakan pendidikan yang inklusif, adil, dan berkualitas.\n\n???? Jenis Beasiswa Internal\nBeasiswa Prestasi Akademik\nDiberikan kepada mahasiswa dengan Indeks Prestasi Kumulatif (IPK) tinggi dan pencapaian akademik lainnya.\n\nBeasiswa Aktivis Organisasi\nDitujukan bagi mahasiswa yang aktif di organisasi kemahasiswaan dan memiliki kontribusi nyata di lingkungan kampus.\n\nBeasiswa Kebutuhan Ekonomi (Beasiswa Bantuan Finansial)\nDiberikan kepada mahasiswa yang berasal dari keluarga dengan kondisi ekonomi menengah ke bawah.\n\nBeasiswa Talenta Non-Akademik\nUntuk mahasiswa dengan prestasi di bidang seni, olahraga, atau kompetisi tingkat nasional maupun internasional.\n\n???? Persyaratan Umum\nTerdaftar aktif sebagai mahasiswa Telkom University.\n\nTidak sedang menerima beasiswa lain (kecuali diizinkan oleh ketentuan).\n\nMemenuhi syarat khusus sesuai jenis beasiswa yang dilamar.\n\nMengunggah dokumen pendukung seperti KHS, surat keterangan tidak mampu, sertifikat prestasi, dan lainnya.\n\n???? Periode Pendaftaran\nPendaftaran beasiswa internal dibuka setiap semester, sesuai dengan pengumuman resmi dari Direktorat Kemahasiswaan atau Unit Pengelola Beasiswa.\n\n???? Informasi &amp; Bantuan\nUntuk informasi lebih lanjut mengenai jenis beasiswa, jadwal, dan mekanisme pendaftaran, mahasiswa dapat mengunjungi:\n\nWebsite: https://student.telkomuniversity.ac.id\n\nEmail: beasiswa@telkomuniversity.ac.id\n\nAtau datang langsung ke Direktorat Kemahasiswaan Telkom University\n\nAyo manfaatkan peluang ini untuk mendukung perjalanan akademikmu di Telkom University!\nBeasiswa bukan hanya soal bantuan dana, tapi juga bentuk penghargaan atas usaha, dedikasi, dan semangatmu dalam meraih prestasi.', 'Beasiswa', 'general', 0, NULL, NULL, '2026-01-27 06:56:00'),
(46, 'peminjaman ruangan', 'peminjaman ruangan difakultas industri kreatif dapat menggunakan aplikasi berbasis web yaitu ifik. untuk cara meminjam ruangan dosen dapat booking dengan cara login terlebih dahulu menggunakan akun dosen kemudian klik menu peminjaman setelah itu tentukan waktu booking', 'peminjaman', 'general', 0, NULL, '2025-06-20 18:31:15', '2025-06-20 04:31:15'),
(49, 'Cuti Akademik', 'Cuti akademik adalah izin yang diberikan oleh Pimpinan UPPS melalui wakil pimpinan UPPS bagi mahasiswa untuk tidak mengikuti seluruh kegiatan akademik dalam waktu 1 (satu) semester penuh.', 'cuti', 'general', 0, NULL, '2025-06-24 11:50:04', '2025-06-23 21:50:04'),
(50, 'Kepala urusan Laboratorium bengkel dan studio', 'Irfan adalah Kepala Urusan Laboratorium Bengkel dan Studio', 'Ka.Ur Lab, kaur lab, Irfan', 'general', 0, NULL, '2025-06-24 15:12:57', '2026-01-29 02:37:08'),
(52, 'Ketersediaan kursi di aula Fik', 'Kursi di aula ada 200 kursi', 'Aula, jumlah kursi', 'general', 0, NULL, '2025-06-24 16:52:12', '2025-06-24 02:52:12'),
(53, 'Ketersedian kursi', 'Kursi yang ada di galeri besar sebanyak 60 kursi', 'Kapasitas galeri, kuota', 'general', 0, NULL, '2025-06-25 10:29:33', '2025-06-24 20:29:33'),
(54, 'Lab Fotografi', 'Lab Fotografi ada di Lantai 5\nAda dua lab fotografi yang hitam dan yang putih\nYang hitam (low key) ruang IK1.05.10\nYang putih (high key) ruang IK1.05.11\nMasing-masing studio terdapat dua lampu studio dan terdapat background juga\nJam operasional Lab Studio dari jam 08.30 - 16.30 hari sabtu dan minggu libur', 'IK1.05.10, IK1.05.11', 'general', 0, NULL, '2025-06-25 10:46:53', '2026-01-20 00:36:23'),
(55, 'Lab praktikum', 'Untuk lab yang biasa digunakan oleh prodi S1 Kriya ada Lab Batik, Lab Tenun, Lab Jahit, dan Lab Pola\r\nLokasi Lab Pola ada di Gedung Sebatik Lantai 1 ruang IK1.01.14, Lab Jahit di Gedung Sebatik Lantai 1 ruang IK1.01.15, dan Lab Tenun di Gedung Sebatik Lantai 1 ruang IK1.01.16', 'Lab, S1 Kriya, Jahit, Pola, Tenun, gedung Sebatik, Praktikum', 'general', 0, NULL, '2025-06-25 11:00:51', '2025-06-24 21:00:51'),
(56, 'Lab FIK Lantai 5', 'Terdapat 4 (empat) Lab di lantai 5 ada Lab Audio, Lab Video dan 2 (dua) Lab Fotografi.\nJam operasional Lab sesuai dengan jam kerja mulai dari jam 08.30-16.30 untuk hari Sabtu dan Minggu Libur.\nPeminjaman Lab bisa dilakukan dengan  input peminjaman melalui IFIK oleh Dosen sesuai dengan kebutuhan pemakaiannya.', 'IK1.05.10, IK1.05.11, IK1.05.12, IK1.05.13', 'general', 0, NULL, '2025-06-25 11:17:12', '2026-02-11 01:57:42'),
(57, 'Jumlah Kelas', 'Saat ini, Fakultas industri kreatif memiliki total 43 kelas praktikum yang tersebar di Telkom University Kampus Bandung, 36 kelas terletak di gedung sebatik fakultas industri kreatif dan 7 kelas di gedung N atau gedung Barung.\n\nSelain itu, untuk kelas kuliah umum terdapat di gedung kuliah umum (GKU) atau gedung tokong nanas Telkom Universtiy', 'jumlah kelas, kelas praktikum, kelas fakultas industri kreatif, kelas fakultas industri kreatif telkom university, kelas FIK, FIK', 'general', 0, NULL, '2025-06-25 11:29:46', '2026-02-05 01:46:08'),
(58, 'TUCC', 'TUCC adalah singkatan dari Telkom University Creative Center. Nama gedungnya adalah gedung karimun. TUCC sendiri terdiri dari tiga lantai dan terdapat beberapa Lab, bengkel dan studio. TUCC berada di selatan Gedung FIK (Fakultas Industri Kreatif).\ndi lantai 1 ada 3 ruangan\n1. Lab Workshop Batik itu ada di IK2.01.22\n2.Bengkel Woodworking itu ad di IK2.01.23\n3.Studio Intermedia IK2.01.27', 'Bengkel', 'general', 0, NULL, '2025-06-25 11:39:21', '2025-08-04 21:32:10'),
(59, 'Student Lounge FIK', 'FIK adalah kepanjangan dari Fakultas Industri Kreatif merupakan salah satu Fakultas yang ada di Universitas Telkom.\nTerdapat tempat untuk berkumpul dan belajar yang dinamakan Student Lounge posisinya ada di lantai 5 Gedung Sebatik FIK.\nAda dua lantai di Student Lounge untuk mengerjakan tugas mahasiswa lantai bawah dan lantai atas.\nUntuk lantai bawah kita bisa berkumpul sambil duduk di panggung atau diatas karpet yang sudah disediakan maupun menggunakan meja dengan kursi yang sudah tertata.\nTerdapat juga ruangan untuk bimbingan atau konsultasi disekitar area student lounge.\nUntuk lantai atas terdapat tempat untuk lesehan apabila mahasiswa mau mengerjakan tugas akan tetapi untuk diatas tidak diperbolehkan menggunakan alas kaki jadi alas kaki bisa disimpan di rak dekat tangga bawah.', 'lantai 5', 'general', 0, NULL, '2025-06-25 11:43:34', '2026-01-23 06:51:44'),
(60, 'Fasilitas Kelas', 'Untuk saat ini, fasilitas kelas di gedung sebatik fakultas industri kreatif terdapat 25 meja dan kursi berlajar, AC, Glassboard. \r\n\r\nselain itu, untuk   presentasi digital, tersedia :\r\nSmartTV yang tersebar di 23 kelas. \r\nlalu Interactive Board di kelas IK1.03.17, IK1.03.18, IK1.04.16, IK1.04.19, IK1.04.11, IK1.04.12 dan IK1.05.08. \r\nlalu Interactive Projector di IK1.03.13, IK1.03.24 dan IK1.04.13. \r\ndan Projector di Kelas IK1.03.16, IK1.04.20 dan IK1.04.22', 'Fasilitas kelas, Fasilitas kelas di FIK, Fasilitas di fakutas industri kreatif telkom university, fasilitas di fakultas industri kreatif', 'general', 0, NULL, '2025-06-25 11:55:47', '2025-06-24 21:55:47'),
(61, 'haki alya', 'haki alya hafsah adalah staff dari Unit layanan akademik/academic service di FIK (Fakultas Industri Kreatif) Telkom University', 'pegawai', 'general', 0, NULL, '2025-06-25 11:59:53', '2025-06-24 21:59:53'),
(62, 'Fakultas Industri Kreatif Telkom University', 'Fakultas Industri Kreatif (FIK) atau School of Creative Industries merupakan salah satu fakultas dari Universitas Telkom (Telkom University) yang bergerak dalam bidang pendidikan Seni Rupa dan Desain yang fokus pada pengembangan pendidikan di sektor Industri Kreatif.\r\n\r\nPada mulanya, Fakultas Industri Kreatif Universitas Telkom merupakan transformasi dari Sekolah Tinggi Seni Rupa dan Desain Indonesia Telkom (STISI Telkom) yang telah berkiprah selama 2 (dua)  dekade lebih sejak didirikan pada tahun 1990  yang terdiri dari 5 program studi (Desain Komunikasi Visual, Desain Interior, Desain Produk, Kriya Tekstil &amp; Mode, Seni Rupa Murni) serta 1 program studi (Desain Komunikasi Visual) lainnya dari Institut Manajemen Telkom (IMT). Tepat pada tanggal 14 Agustus 2013 keduanya telah melebur menjadi Fakultas Industri Kreatif dibawah Universitas Telkom. Pada tahun 2020 telah resmi dibuka program studi baru yakni Program Studi Magister Desain. Saat ini Fakultas Industri Kreatif Universitas Telkom telah memiliki 6 program studi, yaitu:\r\n1) S1 Desain Komunikasi Visual,\r\n2) S1 Desain Interior,\r\n3) S1 Desain Produk (Product Innovation &amp; Management),\r\n4) S1 Kriya (Fashion and Textile Design),\r\n5) S1 Seni Rupa (Visual Arts),\r\n6) S1 Film dan Animasi\r\n7) S2 Desain.\r\n\r\nDengan penerapan kualitas pendidikan, pengajaran serta komitmen yang dijalankan, membawa Fakultas Industri Kreatif Universitas Telkom meraih banyak prestasi dibidang Seni dan Desain. Alumni Fakultas Industri Kreatif telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia.\r\n\r\nFIK telah menghasilkan banyak lulusan yang kiprahnya telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia. \r\n\r\nDalam berkegiatan belajar mengajar, Fakultas Industri Kreatif didukung oleh 30 Tenaga Penunjang Akademik (TPA) dan 174 Dosen. Dosen-dosen FIK tergabung ke dalam 3 kelompok keahlian, yaitu Humagi (Human, Media &amp; Technology), Aectiva (Aesthetic, Culture &amp; Conservation), dan Envisco (Environment, Sustainability &amp; Community). Fakultas Industri Kreatif memiliki 3 Center of Excellence (CoE) yaitu CoE Design Project &amp; Consultancy (HASTALOKA), CoE Digital Assset &amp; Craftsmanship (CIPTALOKA), dan CoE Professional Development &amp; Competencies (KARSALOKA). Selain itu, Fakultas Industri Kreatif juga memiliki prodi di kampus-kampus cabang, yaitu prodi DKV di Jakarta, prodi Desain Produk &amp; DKV di Purwokerto.', 'FIK, Fakultas Industri Kreatif, Sejarah, Profile, Telkom University', 'general', 0, NULL, '2025-06-25 12:07:14', '2025-06-24 22:07:14'),
(63, 'rafli', 'rafli adalah salah satu staff unit Layanan Akademik di Fakultas Industri Kreatif', 'LAA, rafli', 'general', 0, NULL, '2025-06-25 13:33:40', '2025-06-24 23:33:40'),
(64, 'Lab Audio', 'Lab Audio ini terletak di lantai 5 di ruang IK1.05.13. Lab ini biasa di gunakan untuk perkuliahan dan kegiatan lainnya seperti rekaman atau latihan musik.\r\nTerdapat banyak alat yang bisa digunakan di Lab Audio ini seperti mixer, microphone, drum, keyboard, amplifier dll.', 'IK1.05.10, IK1.05.11, IK1.05.12, IK1.05.13', 'general', 0, NULL, '2025-06-25 13:47:54', '2025-06-24 23:47:54'),
(68, 'Rifky', 'Rifky adalah staff Laboran', 'Laboran, Staff, Rifky', 'general', 0, NULL, '2025-07-23 18:27:26', '2025-07-23 04:27:26'),
(69, 'lab fik', 'lab di FIK terdapat 18 dengan rincian sebagai berikut: \n1. Lab Multimedia\n2. Lab Ilustrasi Digital\n3. Lab Pola & Jahit\n4. Lab Material Art dan Intermedia\n5. Lab Sablon\n6. Lab Prototyping dan 3D Print\n7. Lab Bengkel\n8. Lab Fotografi\n9. Lab Green Screen\n10. Lab Audio\n11. Lab Batik\n12. Lab CGI\n13. Lab Ergonomi dan Lighting\n14. Lab Lukis\n15. Lab Mac\n16. Lab Cintiq\n17. Lab Business & Incubator Room\n18. Lab Finishing\n', 'lab, laboratorium', 'general', 0, NULL, '2025-07-31 11:40:11', '2025-07-31 01:25:10'),
(70, 'lab batik', 'Lab Batik merupakan sarana maupun tempat yang memfasilitasi pembuatan sebuah batik. Proses pembuatan dari awal hingga akhir hingga terciptanya sebuah kain batik yang cantik. Selain pembuatan batik, Lab batik juga berfungsi sebagai tempat penelitian maupun kegiatan-kegiatan abdimas. Lab', 'lab, laboratorium', 'general', 0, NULL, '2025-07-31 11:53:20', '2025-07-30 23:06:24'),
(71, 'lab cgi', 'Laboratorium CGI adalah ruangan yang dilengkapi dengan perangkat computer dan peralatan penunjang yang dipergunakan untuk melakukan praktek yang berhubungan dengan multimedia dan grafis.', 'lab, laboratorium', 'general', 0, NULL, '2025-07-31 11:54:37', '2025-07-30 23:06:39'),
(72, 'lab multimedia', 'Lab Multimedia dirancang untuk memfasilitasi mahasiswanya dalam mengerjakan pekerjaan multimedia dengan lancar. Fasilitas yang mendukung seperti software terkini memudahkan mahasiswanya untuk menjangkau software-software yang digunakan pada industri kreatif yang ada.', 'lab, laboratorium', 'general', 0, NULL, '2025-07-31 11:55:45', '2025-07-30 23:05:36'),
(73, 'lab pola dan jahit', 'Lab Pola dan Jahit dirancang dengan space yang cukup besar agar mahasiswa dapat dengan leluasa menggunakan sarana untuk tempat menjahit dan membuat pola.', 'lab, laboratorium, pola, jahit', 'general', 0, NULL, '2025-07-31 14:14:26', '2025-07-31 00:14:26'),
(74, 'lab lukis', 'Studio adalah ruang atau bangunan yang dilengkapi dengan peralatan dan bahan-bahan berdasarkan metode keilmuan tertentu untuk melakukan percobaan ilmiah, penelitian, praktek pembelajaran, kegiatan pengujian, kalibrasi, dan/atau produksi bahan tertentu.', 'lab, laboratorium, lukis', 'general', 0, NULL, '2025-07-31 14:15:16', '2025-07-31 00:15:16'),
(75, 'lab audio', 'Lab Audio merupakan sebuah ruangan yang dirancang untuk melakukan produksi audio seperti dubbing, voice recording, foley art, simulasi audio untuk film, hingga produksi berbagai kebutuhan musik.', 'lab, laboratorium, audio', 'general', 0, NULL, '2025-07-31 14:15:47', '2025-07-31 00:53:24'),
(76, 'lab ergonomi dan lighting', 'Lab. Ergonomi dan Lighting merupakan sebuah ruangan yang dirancang untuk melakukan proses finishing produk dengan menggunakan teknik kuas dan semprot. Asisten Laboratorium adalah orang yang membantu pelaksanaan kegiatan dan teknis operasional, serta mempersiapkan peralatan dan bahan untuk kegiatan praktikum dan penelitian.', 'lab, laboratorium, ergonomi, lighting', 'general', 0, NULL, '2025-07-31 14:16:19', '2025-07-31 01:10:48'),
(77, 'lab prototyping dan 3D', 'Laboratorium adalah ruangan yang dilengkapi dengan peralatan dan bahan-bahan berdasarkan metode keilmuan tertentu untuk melakukan percobaan ilmiah, penelitian, praktek pembelajaran, kalibrasi, dan produksi bahan tertentu. Laboratorium Prototyping dan 3D Printing mewadahi proses pengembangan karya berbasis 3 dimensi. Dengan adanya mesin cetak 3D Print dan mesin prototyping diharapkan bisa membantu meningkatkan kinerja dosen dan mahasiswa di bidang karya 3 dimensi.', 'lab, laboratorium, prototyping, 3d', 'general', 0, NULL, '2025-07-31 14:17:26', '2025-07-31 00:17:26'),
(78, 'lab fotografi', 'Lab Fotografi adalah ruangan yang dirancang untuk melakukan proses pemotretan dengan dilengkapi oleh lampu studio, Table Top, light tent, background,dan properti lainnya untuk pengambilan foto seperti foto model, foto produk dll', 'lab, laboratorium, fotografi', 'general', 0, NULL, '2025-07-31 14:17:57', '2025-07-31 01:23:01'),
(79, 'lab greenscreen', 'Laboratorium Green Screen adalah ruangan yang dirancang untuk melakukan proses produksi video dengan tujuan untuk manipulasi latar atau penayangan. Tersedia alat untuk melengkapi dalam pengambilan gambar seperti red head lamp, lampu Kino FLO, Kamera Video, Lampu LED', 'lab, laboratorium, green screen', 'general', 0, NULL, '2025-07-31 14:18:29', '2025-07-31 00:18:29'),
(80, 'lab material dan intermedia', 'Lab. Material &amp; Intermedia merupakan sebuah ruangan yang dirancang untuk melakukan proses finishing produk dengan menggunakan teknik kuas dan semprot. Asisten Laboratorium adalah orang yang membantu pelaksanaan kegiatan dan teknis operasional, serta mempersiapkan peralatan dan bahan untuk kegiatan praktikum dan penelitian.', 'lab, laboratorium, material, intermedia', 'general', 0, NULL, '2025-07-31 14:19:06', '2025-07-31 00:19:06'),
(81, 'lab bengkel', 'Bengkel merupakan salah satu lab yang berada di FIK yang dilengkapi dengan beberapa peralatan seperti: Mesin table saw, mesin gerinda, mesin bubut kayu, mesin amplas, bench drilling dan lain-lain untuk mendukung mahasiswa dalam mengerjakan pekerjaan pendekatan experimental pada Kuliah Kerja Studio, Proyek Akhir maupun tesis.', 'lab, laboratorium, bengkel', 'general', 0, NULL, '2025-07-31 14:24:01', '2025-07-31 00:24:01'),
(82, 'lab cintiq', 'Lab Komputer Multimedia Cintiq merupakan salah satu dari beberapa lab yang memiliki alat canggih untuk mendukung menggambar secara digital maupun membuat animasi. Dilengkapi dengan Wacom Cintiq disetiap mejanya, Lab ini bisa menampung kurang lebih 25 mahasiswa.', 'lab, laboratorium, cintiq', 'general', 0, NULL, '2025-07-31 15:19:31', '2025-07-31 01:19:31'),
(83, 'Lab Business &amp; Incubator Room', 'Creative Business &amp; Incubator Room adalah ruangan yang dipergunakan untuk menjalankan peran sebagai pusat inkubasi bisnis bertujuan menghasilkan brand bagi pemula yang memiliki kreatifitas dan inovatif.', 'lab, laboratorium, Lab Business,  Incubator Room', 'general', 0, NULL, '2025-07-31 15:20:43', '2025-07-31 01:20:43'),
(84, 'lab finishing', 'Lab. Finishing merupakan sebuah ruangan yang dirancang untuk melakukan proses finishing produk dengan menggunakan teknik kuas dan semprot. Asisten Laboratorium adalah orang yang membantu pelaksanaan kegiatan dan teknis operasional, serta mempersiapkan peralatan dan bahan untuk kegiatan praktikum dan penelitian.', 'lab, laboratorium, finishing', 'general', 0, NULL, '2025-07-31 15:21:33', '2025-07-31 01:22:55'),
(85, 'lab mac', 'Lab Mac merupakan satu dari beberapa lab komputer berbasis sistem operating Macintosh dengan kapasitas yang bisa mendukung sampai dengan 25 mahasiswa dalam proses belajar mengajar. Lab ini juga dilengkapi dengan software-software pendukung terkini yang dapat diakses secara mudah oleh mahasiswanya.', 'lab, laboratorium, mac', 'general', 0, NULL, '2025-07-31 15:22:27', '2025-07-31 01:22:27'),
(86, 'lab mac', 'Lab Mac adalah salah satu laboratorium komputer yang menggunakan sistem operasi Macintosh, dengan kapasitas yang mampu menampung hingga 25 mahasiswa dalam kegiatan pembelajaran. Laboratorium ini juga dilengkapi dengan berbagai perangkat lunak terbaru yang dapat digunakan dengan mudah oleh para mahasiswa.', 'lab, laboratorium, mac', 'general', 0, NULL, '2025-08-05 13:28:22', '2025-08-04 23:28:22'),
(91, 'fik', 'Fakultas Industri Kreatif (FIK) atau School of Creative Industries merupakan salah satu fakultas dari Universitas Telkom (Telkom University) yang bergerak dalam bidang pendidikan Seni Rupa dan Desain yang fokus pada pengembangan pendidikan di sektor Industri Kreatif.\n\nPada mulanya, Fakultas Industri Kreatif Universitas Telkom merupakan transformasi dari Sekolah Tinggi Seni Rupa dan Desain Indonesia Telkom (STISI Telkom) yang telah berkiprah selama 2 (dua)  dekade lebih sejak didirikan pada tahun 1990  yang terdiri dari 5 program studi (Desain Komunikasi Visual, Desain Interior, Desain Produk, Kriya Tekstil &amp; Mode, Seni Rupa Murni) serta 1 program studi (Desain Komunikasi Visual) lainnya dari Institut Manajemen Telkom (IMT). Tepat pada tanggal 14 Agustus 2013 keduanya telah melebur menjadi Fakultas Industri Kreatif dibawah Universitas Telkom. Pada tahun 2020 telah resmi dibuka program studi baru yakni Program Studi Magister Desain. Saat ini Fakultas Industri Kreatif Universitas Telkom telah memiliki 6 program studi, yaitu:\n1) S1 Desain Komunikasi Visual,\n2) S1 Desain Interior,\n3) S1 Desain Produk (Product Innovation &amp; Management),\n4) S1 Kriya (Fashion and Textile Design),\n5) S1 Seni Rupa (Visual Arts),\n6) S1 Film dan Animasi\n7) S2 Desain.\n\nDengan penerapan kualitas pendidikan, pengajaran serta komitmen yang dijalankan, membawa Fakultas Industri Kreatif Universitas Telkom meraih banyak prestasi dibidang Seni dan Desain. Alumni Fakultas Industri Kreatif telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia.\n\nFIK telah menghasilkan banyak lulusan yang kiprahnya telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia. \n\nDalam berkegiatan belajar mengajar, Fakultas Industri Kreatif didukung oleh 30 Tenaga Penunjang Akademik (TPA) dan 174 Dosen. Dosen-dosen FIK tergabung ke dalam 3 kelompok keahlian, yaitu Humagi (Human, Media &amp; Technology), Aectiva (Aesthetic, Culture &amp; Conservation), dan Envisco (Environment, Sustainability &amp; Community). Fakultas Industri Kreatif memiliki 3 Center of Excellence (CoE) yaitu CoE Design Project &amp; Consultancy (HASTALOKA), CoE Digital Assset &amp; Craftsmanship (CIPTALOKA), dan CoE Professional Development &amp; Competencies (KARSALOKA). Selain itu, Fakultas Industri Kreatif juga memiliki prodi di kampus-kampus cabang, yaitu prodi DKV di Jakarta, prodi Desain Produk &amp; DKV di Purwokerto.', 'fik', 'general', 0, NULL, '2026-01-23 07:50:32', '2026-02-03 08:31:38'),
(92, 'siapakah vallen', 'Vallen merupakan Siswa dari SMKN 13 Bandung yang sedang menjalani kegiatan PKL di Telkom University', 'vallen', 'general', 0, NULL, '2026-01-23 07:55:09', '2026-01-23 06:59:45'),
(93, 'siapakah ripky?', 'Staff Laboran', 'siapakah, ripky?', 'general', 0, NULL, '2026-01-23 09:16:34', '2026-01-23 02:16:34'),
(94, 'aku bisa mengajukan peminjaman Lab?', 'Peminjaman Lab bisa dilakukan dengan input peminjaman melalui IFIK oleh Dosen sesuai dengan kebutuhan pemakaiannya.', 'aku, bisa, mengajukan, peminjaman, lab?', 'general', 0, NULL, '2026-01-23 09:17:40', '2026-01-27 07:05:46'),
(95, 'kamu', 'Saya merupakan Machine Learning FIK yang bersedia untuk menyediakan jawaban yang akan anda tanyakan mengenai FIK', 'kamu', 'general', 0, NULL, '2026-01-26 02:59:30', '2026-01-27 01:29:31'),
(96, 'terdapat jurusan fik', 'Fakultas Industri Kreatif (FIK) di Telkom University (Bandung) menyediakan berbagai program studi unggulan di bidang kreatif dan seni. Jurusan sarjana (S1) yang tersedia meliputi Desain Komunikasi Visual (DKV), Desain Interior, Desain Produk, Kriya (Tekstil dan Mode), Seni Rupa, serta Film dan Animasi. \nBerikut adalah daftar lengkap program studi di FIK Telkom University:\nS1 Desain Komunikasi Visual (DKV): Fokus pada desain grafis, multimedia, dan komunikasi visual.\nS1 Desain Interior: Fokus pada perancangan ruang dalam.\nS1 Desain Produk: Fokus pada inovasi dan pengembangan produk fisik.\nS1 Kriya (Tekstil dan Mode): Fokus pada kerajinan tangan, tekstil, dan fashion.\nS1 Seni Rupa: Fokus pada seni murni dan rupa.\nS1 Film dan Animasi: Pengembangan dari peminatan multimedia DKV, berfokus pada produksi film/animasi dan penceritaan.\nS2 Desain (Magister): Program pascasarjana untuk pendalaman ilmu desain. \nFIK juga didukung oleh fasilitas laboratorium yang lengkap dan kelompok keahlian yang berfokus pada budaya, teknologi, serta lingkungan. ', 'terdapat, jurusan, fik', 'general', 0, NULL, '2026-01-26 02:59:34', '2026-01-26 02:00:06'),
(97, 'lokasi lab komputer', 'Lab Komputer FIK terletak di Gedung Industri Kreatif (IK) lantai 2 ruang IK1.02.15. Lab ini dilengkapi dengan komputer terbaru dan software desain untuk mendukung pembelajaran mahasiswa.', 'lab komputer, lokasi, gedung ik, lantai 2, ruang, komputer', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(98, 'irfan kepala urusan lab', 'Irfan adalah Kepala Urusan Laboratorium Bengkel dan Studio di FIK Telkom University. Beliau bertanggung jawab mengkoordinasikan semua kegiatan laboratorium dan bengkel di fakultas.', 'irfan, kepala urusan, kaur, laboran, bengkel, studio, koordinator', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(99, 'jurusan dkv desain komunikasi visual', 'Desain Komunikasi Visual (DKV) adalah program studi S1 di FIK Telkom University yang fokus pada desain grafis, multimedia, dan komunikasi visual. Program ini mengajarkan keterampilan visual storytelling, branding, ilustrasi, fotografi, videografi, dan animasi. Lulusan DKV banyak berkarir sebagai graphic designer, UI/UX designer, illustrator, art director, dan content creator di industri kreatif.', 'dkv, desain komunikasi visual, jurusan, s1, program studi, grafis, multimedia, visual', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(100, 'dimana lab audio lokasi', 'Lab Audio terletak di lantai 5 Gedung IK ruang IK1.05.13. Lab ini dilengkapi dengan peralatan rekaman profesional seperti mixer, microphone, drum, keyboard, amplifier, dan perangkat audio lainnya. Lab Audio biasa digunakan untuk perkuliahan, rekaman musik, podcast, dan latihan band.', 'lab audio, lokasi, lantai 5, gedung ik, ruang, audio, rekaman, musik', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(101, 'lab jahit lokasi peralatan', 'Lab Jahit di FIK menyediakan berbagai peralatan untuk mendukung kegiatan praktikum mahasiswa Kriya Tekstil dan Mode, termasuk mesin jahit industrial, mesin obras, mesin bordir, setrika uap, dan mannequin. Lab ini digunakan untuk praktikum pembuatan busana dan produk tekstil.', 'lab jahit, kriya, tekstil, mode, mesin jahit, obras, peralatan', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(102, 'cara peminjaman lab prosedur', 'Untuk meminjam laboratorium, mahasiswa harus mengajukan permohonan minimal H-2 (2 hari sebelumnya) melalui form peminjaman yang tersedia. Pastikan mengisi data dengan lengkap termasuk tujuan penggunaan, waktu, dan jumlah peserta. Konfirmasi akan diberikan oleh laboran atau koordinator lab.', 'peminjaman lab, prosedur, form, h-2, cara, pengajuan', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(103, 'aula fik kapasitas', 'Aula FIK memiliki kapasitas 200 kursi dan dapat digunakan untuk berbagai acara seperti seminar, workshop, pameran, dan kegiatan kemahasiswaan. Untuk peminjaman aula, hubungi bagian tata usaha FIK.', 'aula fik, kapasitas, 200 kursi, seminar, acara, peminjaman', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(104, 'teguh staff laboran kontak', 'Teguh adalah staff laboran di FIK yang bertanggung jawab dalam pengelolaan dan perawatan peralatan laboratorium. Beliau dapat dihubungi untuk keperluan praktikum, peminjaman alat, atau konsultasi teknis terkait peralatan lab.', 'teguh, staff, laboran, pengelola, peralatan, lab, pak', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-02-10 06:56:09'),
(105, 'vallen pkl siswa smkn', 'Vallen adalah siswa dari SMKN 13 Bandung yang sedang menjalani kegiatan Praktik Kerja Lapangan (PKL) di Telkom University, khususnya di lingkungan FIK. PKL ini merupakan program untuk memberikan pengalaman kerja nyata kepada siswa SMK.', 'vallen, pkl, siswa, smkn 13, praktik kerja lapangan', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(106, 'program studi fik jurusan', 'FIK Telkom University memiliki 7 program studi yaitu: S1 Desain Komunikasi Visual (DKV), S1 Desain Interior, S1 Desain Produk, S1 Kriya (Tekstil dan Mode), S1 Seni Rupa, S1 Film dan Animasi, serta S2 Desain. Semua program studi telah terakreditasi dan didukung oleh fasilitas laboratorium yang lengkap.', 'program studi, jurusan, fik, s1, s2, dkv, interior, produk, kriya, seni rupa, film, animasi', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(107, 'gedung ik industri kreatif', 'Gedung Industri Kreatif (IK) adalah gedung utama FIK yang terdiri dari 5 lantai. Gedung ini menampung berbagai laboratorium, studio, ruang kelas, ruang dosen, dan fasilitas pendukung lainnya untuk kegiatan akademik mahasiswa FIK.', 'gedung ik, industri kreatif, fik, lantai, lokasi, kampus', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(108, 'jam operasional lab jadwal buka', 'Laboratorium FIK umumnya beroperasi pada hari Senin-Jumat pukul 08.00-16.00 WIB. Untuk penggunaan di luar jam operasional atau hari libur, mahasiswa harus mengajukan izin khusus kepada koordinator laboratorium. Jadwal dapat berubah mengikuti kalender akademik.', 'jam operasional, jadwal, lab, buka, senin, jumat, waktu', 'general', 0, NULL, '2026-01-29 09:52:39', '2026-01-29 02:52:39'),
(109, 'jurusan di desain interior', 'Desain interior adalah ilmu perancangan tata letak, dekorasi, dan elemen fisik di dalam bangunan untuk memaksimalkan fungsi, estetika, dan kenyamanan psikologis penggunanya secara ergonomis. Bidang ini menggabungkan seni dan teknik, mencakup pemilihan warna, pencahayaan, perab, dan material, baik untuk hunian maupun komersial.', 'di, desain interior, jurusan, s1, program studi', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(110, 'jurusan dp desain produk', 'Desain produk adalah proses kreatif menciptakan, mengembangkan, dan menyempurnakan produk fungsional serta estetis yang memecahkan masalah pengguna. Ini menggabungkan seni, teknologi, dan riset pasar untuk menghasilkan barang yang bernilai bagi konsumen. Prosesnya mencakup riset, ideasi, pembuatan prototipe, hingga produksi massal.', 'dp, desain produk, jurusan, s1, program studi', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(111, 'jurusan kriya (tekstil dan mode)', 'Kriya (Tekstil dan Mode) adalah disiplin ilmu seni rupa yang berfokus pada penciptaan produk fashion dan tekstil bernilai estetis, fungsional, dan inovatif dengan sentuhan kriya (kerajinan). Bidang ini menggabungkan teknik tradisional seperti batik, tenun, atau sablon dengan teknologi modern, serta menekankan eksplorasi material untuk menghasilkan desain pakaian, tekstil, dan aksesoris yang kreatif.', 'kriya, tekstil, mode, jurusan, s1, program studi', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(112, 'jurusan seni rupa', 'Program Studi S1 Seni Rupa di Telkom University, bagian dari Fakultas Industri Kreatif, merupakan program berakreditasi Unggul yang fokus pada Intermedia Visual Arts (seni rupa intermedia, digital, dan kontemporer). Jurusan ini menggabungkan seni dengan teknologi, menawarkan peminatan seperti Lens Base, Medium Base, dan Studio Lukis untuk mencetak seniman profesional.', 'seni, rupa, seni rupa, jurusan, s1, program studi', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(113, 'jurusan film dan animasi', 'Jurusan Film dan Animasi mempelajari teknik pembuatan karya gambar bergerak (film, animasi 2D/3D, dan game) melalui proses pra-produksi, produksi, hingga pasca-produksi. Mahasiswa diajarkan seni bercerita, sinematografi, desain karakter, penyuntingan, dan manajemen produksi, serta manajemen pemasaran karya kreatif. Lulusan umumnya bergelar S.Sn atau S.I.Kom dengan peluang karier di industri kreatif, studio animasi, rumah produksi, atau game developer.', 'film, animasi, film dan animasi, jurusan, s1, program studi', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(114, 'jurusan s2 desain', 'Magister Desain adalah program studi pascasarjana yang mendalami teori, metodologi, dan praktik desain secara lebih mendalam, fokus pada inovasi, riset, serta integrasi teknologi dan bisnis untuk menciptakan solusi desain yang relevan dengan tantangan kontemporer, membekali lulusan menjadi direktur kreatif, strategist, akademisi, atau wirausahawan di bidang kreatif dengan prospek karier lebih luas.', 'desain, jurusan, s2, program studi, grafis, multimedia, visual', 'general', 0, NULL, '2026-01-29 13:32:23', '2026-01-29 06:32:23'),
(209, 'FIK', 'Fakultas Industri Kreatif (FIK) atau School of Creative Industries merupakan salah satu fakultas dari Universitas Telkom (Telkom University) yang bergerak dalam bidang pendidikan Seni Rupa dan Desain yang fokus pada pengembangan pendidikan di sektor Industri Kreatif.\n\nPada mulanya, Fakultas Industri Kreatif Universitas Telkom merupakan transformasi dari Sekolah Tinggi Seni Rupa dan Desain Indonesia Telkom (STISI Telkom) yang telah berkiprah selama 2 (dua)  dekade lebih sejak didirikan pada tahun 1990  yang terdiri dari 5 program studi (Desain Komunikasi Visual, Desain Interior, Desain Produk, Kriya Tekstil &amp; Mode, Seni Rupa Murni) serta 1 program studi (Desain Komunikasi Visual) lainnya dari Institut Manajemen Telkom (IMT). Tepat pada tanggal 14 Agustus 2013 keduanya telah melebur menjadi Fakultas Industri Kreatif dibawah Universitas Telkom. Pada tahun 2020 telah resmi dibuka program studi baru yakni Program Studi Magister Desain. Saat ini Fakultas Industri Kreatif Universitas Telkom telah memiliki 6 program studi, yaitu:\n1) S1 Desain Komunikasi Visual,\n2) S1 Desain Interior,\n3) S1 Desain Produk (Product Innovation &amp; Management),\n4) S1 Kriya (Fashion and Textile Design),\n5) S1 Seni Rupa (Visual Arts),\n6) S1 Film dan Animasi\n7) S2 Desain.\n\nDengan penerapan kualitas pendidikan, pengajaran serta komitmen yang dijalankan, membawa Fakultas Industri Kreatif Universitas Telkom meraih banyak prestasi dibidang Seni dan Desain. Alumni Fakultas Industri Kreatif telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia.\n\nFIK telah menghasilkan banyak lulusan yang kiprahnya telah banyak memberikan warna pada perkembangan industri kreatif di Indonesia. \n\nDalam berkegiatan belajar mengajar, Fakultas Industri Kreatif didukung oleh 30 Tenaga Penunjang Akademik (TPA) dan 174 Dosen. Dosen-dosen FIK tergabung ke dalam 3 kelompok keahlian, yaitu Humagi (Human, Media &amp; Technology), Aectiva (Aesthetic, Culture &amp; Conservation), dan Envisco (Environment, Sustainability &amp; Community). Fakultas Industri Kreatif memiliki 3 Center of Excellence (CoE) yaitu CoE Design Project &amp; Consultancy (HASTALOKA), CoE Digital Assset &amp; Craftsmanship (CIPTALOKA), dan CoE Professional Development &amp; Competencies (KARSALOKA). Selain itu, Fakultas Industri Kreatif juga memiliki prodi di kampus-kampus cabang, yaitu prodi DKV di Jakarta, prodi Desain Produk &amp; DKV di Purwokerto.', 'FIK, Fakultas Industri Kreatif, Sejarah, Profile, Telkom University, Jelaskan ', 'general', 0, NULL, '2025-06-25 12:07:14', '2026-02-03 07:10:50'),
(334, 'Wacom Cintiq ', 'Wacom Cintiq 13HD adalah komponen display pen tablet profesional dengan fungsi ganda:\nFungsi Monitor: Berfungsi sebagai monitor tambahan yang dapat menampilkan output dari komputer, memberikan workspace tambahan untuk aplikasi dan tool palette\nFungsi Input Device: Sekaligus berfungsi sebagai perangkat input berbasis pena yang memungkinkan pengguna untuk berinteraksi langsung dengan konten digital\nKemampuan: Memungkinkan pengguna menggambar, menulis, atau mengontrol komputer secara langsung dengan stylus pen di permukaan layar. Memberikan pengalaman menggambar yang natural seperti menggambar di atas kertas namun dengan semua keuntungan digital seperti undo, layers, dan berbagai brush digital', 'wacom,cintiq,13hd,display,pen tablet,monitor,input device', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:46:07'),
(335, 'Area Aktif ', 'Area Aktif adalah bagian layar Wacom Cintiq yang merupakan workspace utama dengan fungsi sebagai berikut:\r\nFungsi Menggambar: Area layar ini digunakan sebagai media utama untuk menggambar dengan pena digital, memberikan ruang kerja yang luas untuk kreativitas\r\nFungsi Menulis: Dapat digunakan untuk menulis catatan, anotasi, atau text dengan handwriting recognition pada aplikasi yang mendukung\r\nFungsi Kontrol Kursor: Mengontrol posisi kursor dengan pena digital, memberikan kontrol yang lebih presisi dibandingkan mouse tradisional\r\nPresisi Tinggi: Area ini memungkinkan pengguna untuk membuat desain atau ilustrasi dengan presisi tinggi karena dilengkapi dengan teknologi electromagnetic resonance yang dapat mendeteksi posisi pena dengan akurat hingga tingkat sub-pixel', 'area aktif,layar,workspace,menggambar,menulis,presisi', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:47:59'),
(336, 'Pena Digital ', 'Pena Digital adalah stylus pen yang menjadi alat utama untuk berinteraksi dengan Wacom Cintiq:\nFungsi Menggambar: Digunakan untuk menggambar dengan sensitif terhadap tingkat tekanan, memungkinkan variasi ketebalan garis sesuai tekanan yang diberikan\nFungsi Menulis: Dapat digunakan untuk menulis dengan natural seperti menggunakan pulpen atau pensil biasa\nKontrol Kursor: Mengontrol posisi dan pergerakan kursor pada layar dengan akurasi tinggi\nPressure Sensitivity: Sensitif terhadap tingkat tekanan dengan 2048 levels of pressure atau lebih, sehingga hasil garis dan goresan bisa lebih presisi sesuai gerakan dan tekanan tangan pengguna. Semakin keras tekanan, semakin tebal garisnya, dan sebaliknya', 'pena digital,stylus,pen,tekanan,pressure,menggambar', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-10 07:44:34'),
(337, 'Tombol Pintasan ExpressKeys Wacom Cintiq', 'ExpressKeys adalah tombol-tombol pintasan yang tersedia di sisi Wacom Cintiq untuk mempercepat workflow:\r\n1. Tombol Undo: Digunakan untuk melakukan Undo, yaitu membatalkan langkah atau aksi terakhir yang dilakukan dalam aplikasi, sangat berguna untuk memperbaiki kesalahan dengan cepat\r\n2. Tombol Redo: Digunakan untuk melakukan Redo, yaitu mengulangi kembali langkah atau aksi yang sebelumnya dibatalkan, memungkinkan untuk kembali ke state sebelumnya\r\n3. Tombol Zoom/Rotate: Tombol multifungsi yang dapat digunakan untuk zoom in dan zoom out canvas, mengubah ukuran brush sesuai kebutuhan, serta memutar canvas untuk sudut menggambar yang lebih nyaman\r\n4. Tombol Brush Kecil: Digunakan untuk memperkecil ukuran brush dengan cepat agar garis atau goresan lebih tipis dan presisi untuk detail work\r\n5. Tombol Brush Besar: Digunakan untuk memperbesar ukuran brush agar garis atau goresan lebih tebal dan menonjol, cocok untuk base color atau area fill yang luas', 'expresskeys,tombol pintasan,shortcut,undo,redo,zoom,brush', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(338, 'Port Penghubung Wacom Cintiq', 'Port Penghubung pada Wacom Cintiq yang menghubungkan perangkat ke komputer:\r\nFungsi Koneksi: Port ini berfungsi untuk menyambungkan perangkat Wacom Cintiq ke komputer melalui kabel USB dan HDMI\r\nTransfer Data: Memungkinkan data desain dari komputer dapat ditransfer ke layar Cintiq untuk ditampilkan secara real-time\r\nTransfer Input: Mengirimkan data input dari pena digital kembali ke komputer untuk diproses oleh aplikasi\r\nKoneksi Stabil: Penghubung ini memastikan koneksi yang stabil untuk tampilan layar yang smooth tanpa lag dan input pena yang presisi tanpa delay, sangat penting untuk pengalaman menggambar yang responsive', 'port,penghubung,koneksi,usb,hdmi,kabel,transfer data', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(339, 'Troubleshooting Wacom Cintiq Tidak Menyala', 'Langkah-langkah pemecahan masalah ketika Wacom Cintiq tidak dapat menyala:\r\n1. Periksa koneksi adaptor daya: Pastikan adaptor daya Wacom Cintiq sudah terhubung dengan benar ke stop kontak dan ke port power perangkat, periksa apakah kabel daya tidak longgar, tidak tertekuk, atau salah pasang yang dapat menyebabkan perangkat tidak mendapat pasokan listrik yang cukup\r\n2. Tekan tombol Power: Coba tekan tombol Power pada Wacom Cintiq dengan lebih lama (5-10 detik) untuk menyalakan perangkat, kemudian tunggu beberapa saat hingga layar aktif dan menampilkan gambar, kadang perangkat memerlukan waktu booting yang lebih lama\r\n3. Coba stop kontak lain: Jika perangkat tetap tidak menyala setelah langkah di atas, coba sambungkan adaptor ke stop kontak lain yang berbeda untuk memastikan masalahnya bukan dari stop kontak yang rusak, atau periksa kondisi fisik kabel adaptor dan adaptor itu sendiri untuk memastikan tidak ada kerusakan seperti kabel putus atau adaptor terbakar\r\n4. Periksa koneksi USB dan HDMI: Periksa juga koneksi kabel USB dan HDMI ke komputer untuk memastikan perangkat dapat berfungsi dan menampilkan layar dengan benar, karena Cintiq memerlukan kedua koneksi ini untuk beroperasi penuh, coba cabut dan pasang kembali kedua kabel tersebut', 'troubleshooting,tidak menyala,power,masalah,error,perbaikan,adaptor', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(340, 'Troubleshooting Layar Wacom Cintiq Tidak Menampilkan Gambar', 'Langkah-langkah pemecahan masalah ketika layar Cintiq menyala tetapi tidak menampilkan gambar dari komputer:\r\n1. Periksa koneksi kabel HDMI: Periksa koneksi kabel HDMI antara PC Windows dan Wacom Cintiq untuk memastikan sinyal video tersambung dengan baik, pastikan kabel HDMI terpasang dengan kencang di kedua ujung dan tidak ada kerusakan pada kabel seperti kabel bengkok atau konektor patah\r\n2. Pastikan PC sudah menyala: Pastikan komputer sudah menyala dengan benar dan sudah masuk ke desktop Windows agar ada output yang dapat ditampilkan, jika komputer masih di lock screen atau sleep mode, Cintiq mungkin tidak menampilkan apapun\r\n3. Buka Display Settings: Buka pengaturan tampilan Windows dengan cara klik kanan di desktop dan pilih Display Settings, atau tekan kombinasi keyboard Windows + P untuk membuka menu proyeksi cepat dan mengatur mode layar\r\n4. Pilih mode tampilan yang sesuai: Pilih mode tampilan Extend untuk menggunakan Cintiq sebagai layar kedua yang terpisah dari monitor utama, atau pilih Duplicate untuk menampilkan konten yang sama dengan monitor utama, atau PC Screen Only / Second Screen Only sesuai kebutuhan penggunaan Cintiq, pastikan Cintiq terdeteksi sebagai display kedua dalam Display Settings', 'troubleshooting,layar,tidak tampil,hdmi,display,video,masalah', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(341, 'Troubleshooting Pena Tidak Berfungsi atau Kursor Tidak Mengikuti', 'Langkah-langkah pemecahan masalah ketika pena digital tidak berfungsi atau kursor tidak mengikuti gerakan pena dengan akurat:\r\n1. Periksa instalasi driver: Pastikan driver Wacom sudah terinstal dengan benar di sistem Windows, buka Wacom Desktop Center untuk memastikan perangkat Cintiq terdeteksi oleh sistem dan muncul dalam daftar perangkat, jika tidak terdeteksi mungkin perlu install ulang driver dari situs resmi Wacom\r\n2. Lakukan kalibrasi ulang: Lakukan kalibrasi ulang pena melalui Wacom Desktop Center agar kursor mengikuti gerakan pena dengan akurat dan presisi, kalibrasi yang tidak tepat dapat menyebabkan offset dimana kursor muncul tidak tepat di bawah ujung pena\r\n3. Restart komputer: Jika masalah masih terjadi setelah kalibrasi ulang, coba restart komputer untuk menyegarkan sistem dan driver, kemudian coba kembali menggunakan pena setelah komputer menyala, restart dapat mengatasi masalah temporary pada driver atau sistem', 'troubleshooting,pena,tidak berfungsi,kursor,kalibrasi,driver,masalah', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(342, 'Troubleshooting Wacom Cintiq Tidak Terdeteksi oleh Sistem Windows', 'Langkah-langkah pemecahan masalah ketika Wacom Cintiq tidak terdeteksi oleh sistem operasi Windows:\r\n1. Periksa kabel USB: Periksa kabel USB antara Wacom Cintiq dan komputer untuk memastikan koneksi berjalan dengan baik, pastikan kabel USB terpasang dengan benar di kedua ujung dan tidak ada kerusakan fisik pada kabel\r\n2. Coba port USB lain atau cabut-pasang: Coba gunakan port USB lain pada komputer, preferably port USB 3.0 langsung di motherboard (biasanya di belakang PC), atau lakukan cabut-pasang kembali kabel USB jika koneksi tidak stabil untuk me-refresh koneksi USB, hindari menggunakan USB hub karena dapat menyebabkan masalah power atau bandwidth\r\n3. Restart komputer: Restart komputer jika masalah masih muncul setelah langkah-langkah di atas agar perangkat dapat dikenali kembali oleh sistem Windows, proses restart akan mereset semua USB controller dan device manager, setelah restart buka Device Manager untuk mengecek apakah Cintiq sudah muncul dalam daftar perangkat', 'troubleshooting,tidak terdeteksi,usb,sistem,windows,device,masalah', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(343, 'Perawatan Wacom Cintiq dan PC Windows', 'Panduan perawatan singkat untuk menjaga kondisi dan memperpanjang umur Wacom Cintiq dan PC Windows:\r\n1. Matikan perangkat setelah digunakan: Selalu matikan komputer dan Wacom Cintiq setelah selesai digunakan melalui prosedur shutdown yang benar untuk menghemat energi listrik, mengurangi panas berlebih pada komponen, dan memperpanjang umur komponen elektronik di dalam Cintiq dan PC, jangan langsung cabut kabel saat perangkat masih menyala\r\n2. Simpan pena dengan aman: Simpan pena digital dengan aman di pen stand yang disediakan atau di tempat khusus penyimpanan pen untuk menghindari kerusakan fisik, kehilangan pena, atau ujung pena (nib) yang aus akibat benturan atau tertindih, jangan letakkan pena di sembarang tempat apalagi di atas Cintiq yang sedang menyala\r\n3. Hindari cairan dan benturan: Jauhkan perangkat Wacom Cintiq dari cairan seperti air, kopi, atau minuman lain karena dapat menyebabkan short circuit dan kerusakan permanen pada layar atau komponen elektronik lainnya, hindari juga benturan fisik yang dapat merusak layar LCD, sensor pen, atau komponen internal, gunakan screen protector jika perlu untuk melindungi layar dari goresan', 'perawatan,maintenance,pena,layar,matikan,simpan,hindari cairan', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(344, 'Identitas Wacom Pro Pen (Intuos Pro Pen)', 'Informasi lengkap mengenai identitas dan spesifikasi Wacom Pro Pen yang digunakan dengan Wacom Cintiq:\r\n1. Nama Alat: Wacom Pro Pen - merupakan stylus digital profesional yang dirancang khusus untuk memberikan pengalaman menggambar yang natural dan presisi tinggi\r\n2. Jenis: Pena Digital (Stylus) - kategori alat input yang menggunakan teknologi electromagnetic resonance untuk berkomunikasi dengan tablet tanpa memerlukan baterai\r\n3. Produsen: Wacom Co, Ltd. - perusahaan Jepang yang merupakan pioneer dan market leader dalam industri pen tablet dan display tablet untuk keperluan profesional\r\n4. Fungsi Utama: Alat input utama untuk menggambar, menulis, dan mengontrol kursor dengan tingkat sensitivitas tekanan dan kemiringan pena yang tinggi. Pena ini dapat mendeteksi 2048 levels of pressure atau lebih dan tilt angle hingga 60 derajat, memberikan kontrol yang sangat presisi untuk berbagai teknik menggambar dari line art hingga painting', 'identitas,wacom pro pen,stylus,pena digital,alat', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(345, 'Bagian-Bagian Wacom Intuos Pro Pen', 'Komponen dan bagian-bagian penting pada Wacom Intuos Pro Pen beserta fungsinya:\r\n1. Eraser (Penghapus): Bagian belakang pena yang berfungsi untuk menghapus seperti penghapus pada pensil tradisional, sangat berguna untuk koreksi cepat saat menggambar atau menulis tanpa perlu switch tool dalam aplikasi, cukup balik pena dan gunakan eraser seperti menggunakan penghapus pensil\r\n2. Grip Area: Bagian pegangan pena yang dirancang dengan material khusus dan ergonomis agar nyaman saat digunakan dalam waktu lama, memberikan kontrol yang lebih baik terhadap gerakan pena, dan mengurangi kelelahan tangan atau kram saat bekerja berjam-jam\r\n3. Side Switch (Tombol Samping): Tombol yang terletak di sisi pena dan dapat diprogram untuk berbagai fungsi tambahan sesuai preferensi pengguna, seperti right-click, middle-click, modifier key (Alt, Ctrl, Shift), atau perintah khusus lainnya seperti undo, brush size, dsb melalui Wacom Desktop Center\r\n4. Replaceable Nib (Ujung Pena): Ujung pena yang bisa diganti ketika sudah aus akibat pemakaian, sehingga tidak perlu mengganti seluruh pena dan tetap memberikan respons serta presisi yang optimal, Wacom menyediakan berbagai jenis nib seperti standard, felt tip, flex, dan spring untuk sensasi menggambar yang berbeda', 'bagian,komponen,wacom pro pen,eraser,grip,side switch,nib', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14');
INSERT INTO `knowledge_base` (`id`, `keyword`, `description`, `tags`, `category`, `usage_count`, `last_used`, `created_at`, `updated_at`) VALUES
(346, 'Cara Memegang dan Menggunakan Wacom Pro Pen', 'Panduan teknik yang benar untuk memegang dan menggunakan Wacom Pro Pen agar nyaman dan efektif:\r\n1. Pegang seperti pulpen biasa: Pegang pena dengan cara yang sama seperti memegang pulpen atau pensil biasa, posisikan pena di antara ibu jari dan jari telunjuk dengan jari tengah sebagai support, posisi ini paling natural dan nyaman untuk menggambar dalam waktu lama\r\n2. Atur posisi jari untuk akses tombol: Atur posisi jari agar tombol samping (side switch) mudah dijangkau oleh ibu jari atau jari telunjuk sehingga dapat mengaktifkan shortcut dengan cepat tanpa mengganggu proses menggambar atau mengubah grip, latih muscle memory untuk menekan tombol tanpa melihat\r\n3. Miringkan pena untuk kenyamanan: Posisi pena dapat dan sebaiknya dimiringkan pada sudut yang nyaman untuk menggambar dan navigasi, banyak pena Wacom mendukung tilt sensitivity yang dapat digunakan untuk efek shading atau brush angle yang lebih natural seperti menggambar dengan pensil atau kuas tradisional\r\n4. Gunakan eraser dengan membalik pena: Untuk menghapus, cukup balik pena 180 derajat dan gunakan bagian eraser di belakang pena seperti menggunakan penghapus pada pensil biasa, ini sangat intuitif dan mempercepat workflow tanpa perlu switch tool dalam software', 'cara memegang,cara menggunakan,teknik,pena,grip,ergonomis', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(347, 'Troubleshooting Tekanan Pena Tidak Berfungsi', 'Langkah-langkah pemecahan masalah ketika sensitivitas tekanan pena tidak berfungsi dengan baik:\r\n1. Pastikan driver terinstal dan update: Pastikan driver Wacom sudah terinstal dengan benar di sistem dan diperbarui ke versi terbaru dari situs resmi Wacom untuk mendapatkan bug fix dan peningkatan performa terkini, driver yang outdated dapat menyebabkan masalah pressure sensitivity\r\n2. Periksa pengaturan tekanan: Periksa dan atur pengaturan tekanan pena di Wacom Desktop Center atau Wacom Tablet Properties, pastikan pressure sensitivity tidak dalam mode disabled, atur pressure curve sesuai preferensi (soft, normal, firm), dan test pressure dengan Wacom diagnostic tool\r\n3. Restart aplikasi desain: Tutup dan buka kembali aplikasi desain yang digunakan karena beberapa aplikasi seperti Photoshop atau Clip Studio Paint memerlukan restart untuk mendeteksi perubahan pengaturan pena atau untuk meload ulang driver Wacom, pastikan juga brush settings dalam aplikasi tidak men-disable pressure', 'troubleshooting,tekanan,pressure,pena,tidak berfungsi,sensitivity', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(348, 'Troubleshooting Tombol Samping (Side Switch) Tidak Berfungsi', 'Langkah-langkah pemecahan masalah ketika tombol samping pada pena tidak memberikan respons:\r\n1. Buka Wacom Desktop Center: Buka aplikasi Wacom Desktop Center atau Wacom Tablet Properties dan navigasi ke pengaturan Pen atau Button settings untuk mengecek konfigurasi Side Switch\r\n2. Periksa pengaturan fungsi tombol: Pastikan fungsi tombol Side Switch sudah ditetapkan dengan benar dan tidak dalam mode \"disabled\" atau \"no function\", atur fungsi yang diinginkan seperti Right Click, Middle Click, Keystroke, Modifier, atau fungsi custom sesuai kebutuhan workflow\r\n3. Simpan dan test: Simpan pengaturan yang telah diubah dengan klik tombol OK atau Apply, kemudian uji kembali tombol Side Switch dalam aplikasi untuk memastikan fungsi bekerja dengan baik, coba dalam beberapa aplikasi berbeda untuk memastikan masalahnya bukan dari aplikasi tertentu', 'troubleshooting,side switch,tombol samping,tidak berfungsi,button', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(349, 'Troubleshooting Ujung Pena (Nib) Tidak Berfungsi', 'Langkah-langkah perawatan dan pemecahan masalah untuk ujung pena yang aus atau tidak berfungsi optimal:\r\n1. Periksa dan ganti nib secara rutin: Periksa kondisi ujung pena secara rutin dan visual, jika nib sudah aus (pendek, tidak rata, atau tumpul), segera ganti dengan nib baru untuk memastikan respons tap dan presisi tetap optimal saat digunakan, nib aus dapat menyebabkan scratch pada layar dan input yang tidak akurat\r\n2. Bersihkan permukaan tablet: Pastikan permukaan layar tablet selalu bersih dari debu, kotoran, sidik jari, atau sisa-sisa lain yang bisa mengganggu kinerja pena dan mempercepat keausan nib, gunakan microfiber cloth dan screen cleaner yang aman untuk membersihkan layar secara berkala\r\n3. Gunakan nib yang sesuai rekomendasi: Gunakan nib replacement yang sesuai dengan jenis yang direkomendasikan oleh Wacom untuk model pena yang digunakan agar kompatibilitas terjaga dan pengalaman menggambar tetap maksimal, Wacom menyediakan berbagai jenis nib seperti Standard Black, Felt, Flex, Spring dengan karakteristik berbeda', 'troubleshooting,nib,ujung pena,aus,ganti,bersih,maintenance', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(350, 'Perawatan Wacom Pro Pen', 'Panduan perawatan untuk menjaga kondisi dan memperpanjang umur Wacom Pro Pen:\r\n1. Simpan di pen stand atau letakkan rata: Saat tidak digunakan, simpan pena pada pen stand yang disediakan atau letakkan secara horizontal rata di atas meja untuk menjaga bentuk dan fungsi pena tetap optimal, penyimpanan yang baik juga membuat pena mudah ditemukan saat dibutuhkan dan terhindar dari jatuh\r\n2. Jangan simpan dengan ujung menyentuh permukaan: Jangan menyimpan pena dengan posisi vertikal dimana ujung nib menyentuh permukaan keras seperti meja karena dapat menyebabkan nib cepat aus, bengkok, atau bahkan rusak, selalu simpan horizontal atau di pen stand khusus\r\n3. Jangan tinggalkan di atas tablet: Jangan meninggalkan pena di atas permukaan tablet Cintiq yang sedang menyala karena dapat mengganggu kursor dan menyebabkan cursor drift, ghost clicking, atau pointer yang tidak stabil pada layar, sensor akan terus mendeteksi pena yang berada di dekat permukaan meskipun tidak disentuh', 'perawatan,maintenance,pena,simpan,pen stand,nib,care', 'general', 0, NULL, '2026-02-05 09:32:14', '2026-02-05 02:32:14'),
(352, 'Cara penggunaan Wacom Cintiq', 'Berikut adalah panduan lengkap Cara Penggunaan Wacom Cintiq beserta instalasi apa saja yang diperlukan:\r\n\r\nLANGKAH 1: MENGHUBUNGKAN PERANGKAT KE KOMPUTER\r\n1. Sambungkan kabel USB Cintiq ke port USB komputer (sebaiknya USB 3.0)\r\n2. Sambungkan kabel HDMI ke port HDMI komputer\r\n3. Sambungkan adaptor daya ke port power Wacom Cintiq\r\n4. Colokkan adaptor ke stop kontak listrik\r\n\r\nLANGKAH 2: MENYALAKAN PERANGKAT\r\n1. Tekan tombol Power pada komputer PC Windows\r\n2. Tunggu sistem Windows menyala sepenuhnya (30 detik - 2 menit)\r\n3. Setelah komputer menyala, tekan tombol Power pada Wacom Cintiq\r\n\r\nLANGKAH 3: INSTALASI DRIVER WACOM\r\n1. Gunakan mouse dan keyboard untuk operasi awal\r\n2. Buka browser dan kunjungi https://www.wacom.com/support\r\n3. Unduh driver untuk model Wacom Cintiq DT1300 sesuai OS Windows\r\n4. Jalankan file installer sebagai Administrator\r\n5. Ikuti langkah instalasi dan restart komputer jika diminta\r\n\r\nLANGKAH 4: KALIBRASI PENA DIGITAL\r\n1. Buka aplikasi Wacom Desktop Center\r\n2. Pilih menu Calibrate untuk model Cintiq 13HD\r\n3. Sentuh titik target yang muncul di layar (4-9 titik)\r\n4. Selesaikan semua titik dan tekan Finish\r\n5. Simpan pengaturan kalibrasi\r\n\r\nLANGKAH 5: PENGUJIAN FUNGSIONALITAS\r\n1. Buka aplikasi desain (Photoshop, Illustrator, Krita, dll.)\r\n2. Gunakan pena digital untuk menggambar berbagai stroke\r\n3. Periksa tracking kursor mengikuti gerakan pena\r\n4. Uji sensitivitas tekanan dengan berbagai tingkat tekanan\r\n\r\nLANGKAH 6: MENGHUBUNGKAN KE INTERNET TEL-U CONNECT\r\n1. Colokkan dongle Wi-Fi USB ke komputer\r\n2. Klik ikon Network di taskbar dan pilih TEL-U CONNECT\r\n3. Klik Connect dan masukkan username/password\r\n4. Pastikan status Connected\r\n\r\nLANGKAH 7: MENJALANKAN APLIKASI DESAIN\r\n1. Klik logo Windows atau buka desktop\r\n2. Pilih aplikasi desain yang dibutuhkan\r\n3. Tunggu aplikasi terbuka sepenuhnya\r\n\r\nLANGKAH 8: MENUTUP APLIKASI\r\n1. Simpan semua pekerjaan (Ctrl+S)\r\n2. Klik tombol Close (X) atau tekan Alt+F4\r\n3. Pastikan aplikasi tertutup dari taskbar\r\n\r\nLANGKAH 9: MENGATUR KECERAHAN LAYAR\r\n1. Tekan FN + F5 (kurangi) atau FN + F6 (tambah)\r\n2. Atau buka Settings > System > Display\r\n3. Atur slider Brightness sesuai kenyamanan mata\r\n4. Tutup Settings (pengaturan otomatis tersimpan)\r\n\r\nLANGKAH 10: PENGATURAN ERGONOMIS\r\n1. Atur kemiringan Cintiq menggunakan stand (10-30 derajat)\r\n2. Sejajarkan layar dengan pandangan mata atau sedikit di bawah\r\n3. Duduk tegak dengan punggung bersandar, kaki menapak rata\r\n4. Simpan posisi yang nyaman untuk penggunaan berulang\r\n\r\nLANGKAH 11: MEMATIKAN SISTEM\r\n1. Tutup dan simpan semua aplikasi\r\n2. Klik logo Windows > Power > Shut Down\r\n3. Setelah komputer mati, tekan tombol Power Wacom Cintiq\r\n4. Cabut adaptor dari stop kontak jika tidak digunakan lama\r\n5. Pastikan semua lampu indikator padam dan rapikan kabel\r\n\r\nCATATAN PENTING:\r\n- Gunakan stop kontak stabil, hindari extension cord\r\n- Pastikan driver versi terbaru untuk performa optimal\r\n- Kalibrasi ulang jika merasa akurasi pena berkurang\r\n- Simpan pekerjaan secara berkala selama bekerja', 'wacom cintiq,dt1300,panduan lengkap,11 langkah,penggunaan,setup,kalibrasi,driver,ergonomis,windows,tel-u connect,pena digital', 'general', 0, NULL, '2026-02-05 09:40:24', '2026-02-05 02:40:24'),
(353, 'Lab Digital Ilustrasi', 'Laboratorium Digital Ilustrasi di Telkom University utamanya didukung oleh Lab Cintiq (di bawah Prodi DKV/FIK) yang menyediakan perangkat pen display canggih untuk menggambar digital, ilustrasi, dan desain kreatif. Fasilitas ini fokus pada pengembangan konten digital, pengolahan multimedia, dan penggunaan software Adobe (Illustrator, Photoshop) untuk hasil karya berkualitas tinggi. Lab ini Terdapat di Lantai 3 Gedung FIK pada ruangan IK.03.08', 'lab, lokasi, dimana, apa, saja', 'general', 0, NULL, '2026-02-05 09:53:13', '2026-02-05 02:53:13'),
(356, 'Apple iMac', 'Apple iMac adalah komputer desktop yang diproduksi oleh Apple Inc dengan sistem operasi MacOS. Perangkat ini berfungsi untuk mengolah data, menjalankan aplikasi, dan menunjang aktivitas kerja. iMac dilengkapi dengan layar Retina 5K beresolusi tinggi, kamera HD FaceTime 1080p dengan mikrofon untuk panggilan video dan perekaman, serta speaker berkualitas untuk keluaran audio. Di bagian belakang terdapat Port USB Type-A untuk menghubungkan perangkat seperti flashdisk, keyboard, mouse, dan printer; Port Thunderbolt 2 untuk transfer data berkecepatan tinggi; Port Ethernet (LAN) untuk koneksi jaringan stabil; Port Daya untuk pasokan listrik; dan Tombol Power untuk menyalakan/mematikan komputer.', 'imac,komputer,apple,desktop,macos', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(357, 'Cara Menyalakan iMac', 'Untuk menyalakan komputer iMac, ikuti langkah berikut: Pertama, pastikan kabel daya iMac terhubung dengan benar ke sumber listrik utama yang tersedia. Kemudian tekan tombol Power yang terletak pada bagian belakang iMac untuk menyalakan perangkat komputer. Setelah komputer menyala, pilih akun \"Kuliah\" pada layar login macOS, tekan tombol Enter atau klik Sign In, lalu tunggu hingga sistem selesai memuat dan menampilkan desktop.', 'imac,menyalakan,power,login', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(358, 'Koneksi Internet iMac', 'Untuk menghubungkan iMac ke internet, klik ikon Wi-Fi di pojok kanan atas layar komputer untuk membuka daftar jaringan yang tersedia. Pilih jaringan \"Tel-U Connect\" dari daftar jaringan Wi-Fi yang muncul. Masukkan username dan password sesuai dengan akun yang telah diberikan, kemudian klik Connect untuk menghubungkan komputer ke internet. Pastikan Wi-Fi dalam kondisi aktif dan ikon jaringan terlihat pada menu bar.', 'imac,wifi,internet,tel-u connect', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(359, 'Menjalankan Aplikasi iMac', 'Untuk menjalankan aplikasi di iMac, pastikan iMac sudah menyala dan berhasil masuk ke desktop macOS dengan normal tanpa kendala. Klik Launchpad untuk menampilkan seluruh daftar aplikasi yang tersedia pada sistem. Pilih aplikasi yang ingin dijalankan dengan cara mengklik dua kali pada ikon aplikasi tersebut, maka aplikasi akan terbuka dan siap digunakan. Untuk menutup aplikasi, klik kanan pada ikon aplikasi yang sedang berjalan di bar bawah sistem, lalu pilih menu Quit/Keluar untuk menghentikan proses aplikasi tersebut.', 'imac,aplikasi,launchpad,menjalankan', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(360, 'Troubleshooting iMac Tidak Menyala', 'Jika iMac tidak menyala, lakukan pemeriksaan berikut: Periksa kabel daya apakah sudah terhubung dengan benar ke komputer dan sumber listrik. Pastikan sumber listrik dalam kondisi aktif dan berfungsi normal. Tekan tombol Power kembali selama beberapa detik untuk mencoba menyalakan kembali. Jika masih tidak menyala, coba gunakan stop kontak lain atau periksa kondisi kabel power.', 'imac,troubleshooting,tidak menyala,power', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(361, 'Troubleshooting Login iMac', 'Jika tidak bisa login ke sistem iMac, pastikan username dan password dimasukkan dengan benar sesuai dengan akun yang telah diberikan. Periksa tombol Caps Lock pada keyboard untuk memastikan tidak aktif saat mengetik password karena password bersifat case-sensitive. Jika lupa password atau mengalami kendala saat masuk yang tidak dapat diatasi, segera hubungi administrator atau petugas IT yang bertugas untuk mendapatkan bantuan reset password atau pengecekan akun.', 'imac,troubleshooting,login,password', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(362, 'Troubleshooting Koneksi Internet iMac', 'Jika iMac tidak bisa terhubung ke internet, lakukan langkah berikut: Pastikan WiFi dalam kondisi aktif dan ikon jaringan terlihat pada menu bar di pojok kanan atas. Pilih ulang jaringan \"Tel-U Connect\" dari daftar jaringan WiFi yang tersedia. Masukkan kembali username dan password dengan benar sesuai akun yang dimiliki, perhatikan penulisan huruf besar dan kecil. Jika masih gagal terhubung, lakukan restart iMac dan coba sambungkan kembali ke jaringan setelah komputer menyala kembali.', 'imac,troubleshooting,internet,wifi', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(363, 'Troubleshooting Aplikasi iMac', 'Jika aplikasi di iMac tidak bisa dibuka atau mengalami masalah, tutup aplikasi yang bermasalah dengan klik kanan pada dock lalu pilih Quit. Kemudian buka kembali aplikasi tersebut untuk mencoba lagi. Jika masalah berlanjut, lakukan restart iMac untuk menyegarkan sistem dan memperbaiki gangguan sementara yang mungkin terjadi. Pastikan aplikasi sudah terinstal dengan benar dan versi aplikasi kompatibel dengan sistem macOS yang digunakan.', 'imac,troubleshooting,aplikasi,restart', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(364, 'Perawatan iMac', 'Untuk merawat iMac agar tetap optimal, gunakan iMac di ruangan yang bersih, kering, dan memiliki sirkulasi udara yang baik agar perangkat tidak overheat dan tetap bekerja secara optimal. Jangan mematikan komputer secara paksa dengan mencabut listrik atau menekan tombol power terlalu lama karena dapat menyebabkan kerusakan sistem dan kehilangan data. Selalu matikan komputer menggunakan prosedur shutdown yang benar melalui menu Apple > Shut Down setelah selesai digunakan untuk menjaga kinerja dan umur perangkat.', 'imac,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:06:33', '2026-02-05 03:06:33'),
(365, 'Apple Magic Keyboard', 'Apple Magic Keyboard adalah keyboard wireless (Bluetooth) yang diproduksi oleh Apple Inc. Keyboard ini berfungsi sebagai perangkat input untuk mengetik dan memberikan perintah pada komputer Mac. Di bagian atas terdapat tombol fungsi seperti: tombol untuk mengatur kecerahan layar Mac, tombol Mission Control untuk melihat gambaran lengkap aplikasi yang berjalan termasuk Dashboard, tombol Launchpad untuk melihat semua aplikasi, tombol media untuk kontrol playback (play/pause/skip), tombol volume (mute, kurangi, tambah volume), dan tombol eject untuk mengeluarkan disk. Keyboard ini dilengkapi tombol Power (On/Off) di bagian samping dan port pengisian daya Lightning/USB-C.', 'magic keyboard,apple,keyboard,wireless,bluetooth', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(366, 'Menghubungkan Magic Keyboard', 'Untuk menghubungkan Apple Magic Keyboard ke Mac, geser tombol power pada keyboard hingga terlihat warna hijau sebagai indikator bahwa perangkat telah berhasil diaktifkan dan daya sudah menyala dengan sempurna. Pastikan keyboard mendapatkan pasokan daya yang cukup untuk dapat terhubung dengan komputer secara stabil. Tunggu beberapa detik hingga Mac secara otomatis mengenali keyboard yang terhubung dan melakukan proses penyesuaian sistem (pairing otomatis). Setelah koneksi berhasil, keyboard siap digunakan secara normal untuk mengetik dan menjalankan berbagai perintah pada komputer.', 'magic keyboard,pairing,koneksi,bluetooth', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(367, 'Cek Status Magic Keyboard', 'Untuk mengecek status koneksi dan baterai Magic Keyboard, buka menu System Settings pada Mac untuk mengakses pengaturan sistem. Pilih menu Bluetooth untuk melihat daftar perangkat yang tersedia dan terhubung ke Mac. Pastikan Magic Keyboard dalam kondisi terhubung (Connected) dan dapat digunakan secara normal. Di menu ini juga dapat dilihat level baterai keyboard untuk memastikan daya masih mencukupi dan tidak perlu segera diisi ulang.', 'magic keyboard,status,baterai,bluetooth', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(368, 'Troubleshooting Magic Keyboard Tidak Terdeteksi', 'Jika Magic Keyboard tidak terdeteksi oleh Mac, lakukan langkah berikut: Pastikan Apple Magic Keyboard dalam keadaan menyala dengan indikator hijau terlihat sebagai tanda daya aktif pada tombol power. Pastikan fitur Bluetooth pada Mac telah aktif dan siap digunakan dengan mengecek di System Settings > Bluetooth. Dekatkan keyboard ke Mac dengan jarak tidak lebih dari 1 meter, lalu tunggu beberapa saat hingga terdeteksi otomatis oleh sistem dan dapat digunakan untuk mengetik.', 'magic keyboard,troubleshooting,tidak terdeteksi,bluetooth', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(369, 'Troubleshooting Magic Keyboard Tidak Merespons', 'Jika Magic Keyboard tidak bisa digunakan atau tidak merespons input, matikan keyboard dengan menggeser tombol power ke posisi OFF. Tunggu beberapa detik (minimal 5-10 detik), lalu nyalakan kembali keyboard dengan menggeser tombol power hingga muncul indikator hijau. Pastikan baterai keyboard masih mencukupi dengan mengecek level baterai di System Settings > Bluetooth. Hubungkan kembali keyboard dengan Mac melalui Bluetooth jika koneksi terputus, dan pastikan tidak ada interferensi dari perangkat elektronik lain.', 'magic keyboard,troubleshooting,tidak merespons', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(370, 'Troubleshooting Koneksi Magic Keyboard Terputus', 'Jika koneksi Magic Keyboard terputus secara tiba-tiba saat digunakan, pastikan jarak keyboard dengan Mac tidak terlalu jauh (maksimal 10 meter) supaya sinyal Bluetooth tetap kuat dan stabil. Hindari gangguan dari perangkat elektronik lain seperti microwave, router WiFi, atau perangkat Bluetooth lain yang bisa menghalangi atau mengganggu koneksi. Matikan lalu nyalakan kembali keyboard untuk menyegarkan koneksi Bluetooth. Jika masih bermasalah, restart Mac agar semua pengaturan Bluetooth dimuat ulang dan koneksi dapat diperbaiki.', 'magic keyboard,troubleshooting,koneksi terputus', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(371, 'Perawatan Magic Keyboard', 'Untuk merawat Magic Keyboard, matikan keyboard saat tidak digunakan untuk menghemat daya dan mencegah kerusakan pada komponen internal, ini juga membantu menjaga koneksi Bluetooth tetap stabil. Isi daya baterai keyboard secara rutin menggunakan kabel Lightning/USB-C, bahkan sebelum habis total, agar umur baterai lebih panjang dan performa tetap optimal. Gunakan charger sesuai petunjuk produsen untuk menghindari kerusakan baterai. Jauhkan keyboard dari cairan seperti air, kopi, atau minuman lain karena dapat merusak sirkuit internal. Hindari benturan keras yang dapat merusak tombol atau komponen internal. Menangani keyboard dengan hati-hati akan membuat perangkat lebih awet.', 'magic keyboard,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:06:45', '2026-02-05 03:06:45'),
(372, 'Apple Magic Mouse', 'Apple Magic Mouse adalah mouse wireless (Bluetooth) yang diproduksi oleh Apple Inc. Perangkat ini berfungsi sebagai perangkat input untuk menggerakkan kursor, memilih objek, dan menjalankan perintah pada komputer Mac. Magic Mouse memiliki permukaan sentuh (touch surface) di bagian atas yang mendukung berbagai gesture. Fungsi utama meliputi: klik kiri dan klik kanan untuk memilih dan mengeksekusi perintah, scroll ke atas dan bawah dengan gerakan jari, serta berbagai gesture sentuh (swipe) yang dapat disesuaikan seperti berpindah antar desktop, zoom in/out, membuka Mission Control, rotate, dan gesture khusus aplikasi. Mouse ini dilengkapi tombol Power On/Off di bagian bawah dan port Lightning/USB-C untuk pengisian daya.', 'magic mouse,apple,mouse,wireless,bluetooth', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(373, 'Menghubungkan Magic Mouse', 'Untuk menghubungkan Apple Magic Mouse ke Mac, geser tombol power di bagian bawah mouse dengan perlahan hingga warna hijau terlihat, yang menandakan bahwa mouse sudah menyala dan siap digunakan. Pastikan mouse dalam kondisi bertenaga dan baterai mencukupi. Tunggu beberapa detik hingga Mac secara otomatis mengenali mouse melalui koneksi Bluetooth (proses pairing otomatis). Setelah terdeteksi dan terhubung, mouse siap digunakan untuk menggerakkan kursor, melakukan klik, dan menjalankan berbagai gesture yang tersedia.', 'magic mouse,pairing,koneksi,bluetooth', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(374, 'Cek Status Magic Mouse', 'Untuk mengecek status koneksi dan baterai Magic Mouse, buka menu System Settings pada Mac untuk mengakses pengaturan sistem. Pilih menu Bluetooth untuk melihat daftar perangkat yang tersedia dan terhubung ke komputer. Pastikan Magic Mouse dalam kondisi terhubung (Connected) agar dapat digunakan secara normal untuk menggerakkan kursor dan melakukan input. Di menu ini juga dapat dilihat level baterai mouse untuk memantau kapan perlu dilakukan pengisian daya agar tidak kehabisan baterai saat digunakan.', 'magic mouse,status,baterai,bluetooth', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(375, 'Pengisian Daya Magic Mouse', 'Untuk mengisi daya Magic Mouse, hubungkan kabel Lightning/USB-C ke port pengisian daya yang terletak di bagian bawah mouse, lalu sambungkan ujung lainnya ke Mac atau adaptor daya hingga baterai terisi penuh. Perlu diperhatikan bahwa selama proses pengisian daya berlangsung, Magic Mouse tidak bisa digunakan karena posisi port berada di bawah sehingga mouse tidak dapat diletakkan rata. Tunggu hingga baterai benar-benar penuh (biasanya memerlukan waktu sekitar 2 jam untuk pengisian penuh) sebelum mulai mengoperasikannya kembali.', 'magic mouse,charging,pengisian daya', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(376, 'Troubleshooting Magic Mouse Tidak Bergerak', 'Jika kursor tidak bergerak atau Magic Mouse tidak merespons, matikan Magic Mouse dengan menggeser tombol power di bagian bawah ke posisi OFF. Tunggu beberapa detik (minimal 5-10 detik), lalu nyalakan kembali mouse dengan menggeser tombol ke posisi ON hingga terlihat indikator hijau. Pastikan permukaan mouse (sensor optik di bagian bawah) bersih dan kering, tidak ada debu atau kotoran yang menghalangi sensor. Gunakan mouse pada permukaan datar yang tidak terlalu licin atau terlalu kasar, hindari permukaan kaca atau cermin karena sensor tidak dapat bekerja optimal.', 'magic mouse,troubleshooting,tidak bergerak', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(377, 'Troubleshooting Koneksi Magic Mouse Terputus', 'Jika koneksi Magic Mouse terputus secara tiba-tiba, pastikan jarak Magic Mouse tidak terlalu jauh dari Mac (maksimal 10 meter untuk koneksi Bluetooth optimal). Hindari gangguan sinyal dari perangkat Bluetooth lain atau perangkat elektronik seperti router WiFi yang dapat menyebabkan interferensi. Matikan dan nyalakan kembali Magic Mouse dengan menggeser tombol power untuk me-refresh koneksi Bluetooth. Jika masalah berlanjut, restart Mac untuk memuat ulang sistem Bluetooth dan coba sambungkan kembali mouse setelah komputer menyala.', 'magic mouse,troubleshooting,koneksi terputus', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(378, 'Troubleshooting Baterai Magic Mouse', 'Jika baterai Magic Mouse lemah atau habis yang ditandai dengan mouse tidak merespons atau bergerak tidak lancar, hubungkan Magic Mouse ke Mac atau adaptor daya menggunakan kabel Lightning/USB-C yang sesuai. Tunggu hingga proses pengisian daya berjalan, biasanya memerlukan waktu sekitar 2 jam untuk pengisian penuh. Periksa status baterai melalui menu Bluetooth di Mac dengan membuka System Settings > Bluetooth untuk melihat persentase baterai. Lakukan pengisian daya secara rutin sebelum baterai benar-benar habis untuk menjaga performa mouse tetap optimal.', 'magic mouse,troubleshooting,baterai', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(379, 'Perawatan Magic Mouse', 'Untuk merawat Magic Mouse, matikan mouse saat tidak digunakan untuk menghemat daya baterai dan mencegah kerusakan pada komponen internal. Isi daya baterai secara rutin menggunakan kabel Lightning/USB-C, bahkan sebelum habis total, agar performa mouse tetap optimal dan umur baterai lebih panjang. Hindari menunggu hingga baterai benar-benar habis sebelum mengisi daya. Jauhkan mouse dari cairan seperti air, kopi, atau minuman lain karena cairan dapat merusak sirkuit internal dan sensor optik. Hindari benturan keras yang bisa merusak tombol, sensor, atau komponen internal lainnya. Bersihkan permukaan mouse secara berkala dengan kain lembut agar sensor tetap berfungsi optimal.', 'magic mouse,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:07:01', '2026-02-05 03:07:01'),
(380, 'Wacom Intuos Pro', 'Wacom Intuos Pro adalah pen tablet yang diproduksi oleh Wacom Co, Ltd. Perangkat ini berfungsi sebagai perangkat input berbasis pena (stylus) yang digunakan untuk menggambar, menulis, dan mengontrol kursor pada komputer dengan presisi tinggi. Tablet memiliki Active Area yang sensitif terhadap sentuhan dan tekanan pena, memungkinkan garis yang digambar berubah sesuai tingkat tekanan. Dilengkapi dengan Pena Digital Wacom yang mampu mendeteksi tingkat tekanan untuk menghasilkan variasi ketebalan garis. Terdapat 10 tombol pintasan (ExpressKeys) yang dapat dikonfigurasi untuk berbagai fungsi seperti undo, redo, klik kanan, enter, zoom, scroll, ganti alat, dan lainnya. Tablet juga memiliki Touch Ring untuk mengatur ukuran brush, zoom, atau scroll. Port penghubung USB digunakan untuk menghubungkan ke komputer sekaligus sebagai jalur pengisian daya.', 'wacom,intuos pro,pen tablet,stylus', 'general', 0, NULL, '2026-02-05 10:07:56', '2026-02-05 03:07:56'),
(381, 'Menghubungkan Wacom Intuos Pro', 'Untuk menghubungkan Wacom Intuos Pro ke komputer, pertama hubungkan kabel USB dari tablet ke port USB komputer dan pastikan kedua ujung kabel terpasang dengan benar dan kuat. Tunggu beberapa saat hingga komputer mendeteksi perangkat baru. Tekan tombol On/Off yang terletak di sisi kiri tablet dengan lembut namun tegas untuk mengaktifkan tablet. Jika installer driver Wacom belum terpasang di Mac, buka browser dan akses website resmi Wacom (wacom.com) untuk mengunduh driver yang sesuai dengan tipe Intuos Pro yang digunakan. Setelah selesai diunduh, jalankan proses instalasi dan ikuti petunjuk hingga instalasi selesai sepenuhnya. Jika muncul permintaan untuk merestart Mac, lakukan restart agar semua pengaturan dan driver terpasang dengan benar. Buka Wacom Desktop Center untuk memeriksa status tablet, pastikan tertulis \"Connected\" dan nama perangkat terbaca sesuai tipe tablet. Lakukan tes gerakan pena di Active Area untuk memastikan tablet merespons dengan baik.', 'wacom,koneksi,instalasi,driver', 'general', 0, NULL, '2026-02-05 10:07:56', '2026-02-05 03:07:56'),
(382, 'Troubleshooting Wacom Tidak Terdeteksi', 'Jika Wacom Intuos Pro tidak terdeteksi oleh komputer, lakukan pemeriksaan berikut: Pertama, pastikan kabel USB terhubung dengan benar ke tablet dan komputer, periksa apakah ada kerusakan pada kabel atau port USB. Pastikan tablet dalam kondisi menyala dengan menekan tombol power dan melihat indikator LED menyala. Coba gunakan port USB lain pada komputer karena mungkin port yang digunakan bermasalah. Restart komputer dan sambungkan kembali tablet setelah komputer menyala. Periksa apakah driver Wacom sudah terinstal dengan benar melalui Wacom Desktop Center. Jika masih bermasalah, uninstall dan install ulang driver Wacom dari website resmi.', 'wacom,troubleshooting,tidak terdeteksi', 'general', 0, NULL, '2026-02-05 10:07:56', '2026-02-05 03:07:56'),
(383, 'Troubleshooting Wacom ExpressKeys', 'Jika tombol pintasan (ExpressKeys) pada Wacom Intuos Pro tidak berfungsi, lakukan langkah berikut: Buka Wacom Desktop Center di Mac dan periksa pengaturan tombol ExpressKeys. Pastikan setiap tombol telah diberi fungsi sesuai kebutuhan dengan mengklik pada tombol yang ingin dikonfigurasi dan memilih fungsi yang diinginkan dari menu dropdown. Fungsi yang dapat diatur antara lain: Undo, Redo, Klik Kanan, Klik Kiri/Enter, Zoom In, Zoom Out, Scroll, Pan (Hand Tool), Switch Tool (Brush/Eraser), dan lainnya. Setelah selesai mengatur, simpan pengaturan dengan mengklik tombol Apply atau OK. Uji kembali setiap tombol untuk memastikan semuanya bekerja dengan benar sesuai konfigurasi yang telah dibuat. Jika masih tidak berfungsi, restart tablet dan komputer.', 'wacom,troubleshooting,expresskeys', 'general', 0, NULL, '2026-02-05 10:07:56', '2026-02-05 03:07:56'),
(384, 'Perawatan Wacom Intuos Pro', 'Untuk merawat Wacom Intuos Pro, matikan tablet saat tidak digunakan untuk menghemat daya dan menjaga umur perangkat lebih lama. Simpan pena (stylus) pada pen stand atau tempat yang aman agar tidak hilang, jatuh, atau rusak karena benturan. Jangan meletakkan pena di atas Active Area tablet saat tidak digunakan karena dapat mengganggu kursor dan membuat mouse tidak bisa digunakan. Hindari paparan cairan seperti air, kopi, atau minuman lain yang dapat merusak komponen elektronik. Jauhkan dari debu berlebih dengan menutup tablet menggunakan cover saat tidak digunakan. Hindari benturan keras atau tekanan berlebih pada permukaan Active Area. Bersihkan permukaan tablet secara berkala dengan kain lembut dan kering untuk menjaga sensitivitas tetap optimal.', 'wacom,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:07:56', '2026-02-05 03:07:56'),
(385, 'Wacom Pro Pen', 'Wacom Pro Pen adalah pena digital (stylus) yang diproduksi oleh Wacom Co, Ltd sebagai alat input utama untuk menggambar, menulis, dan mengontrol kursor dengan tingkat tekanan dan kemiringan pena yang akurat. Bagian-bagian pena meliputi: Eraser (Penghapus) di bagian belakang yang berfungsi mirip penghapus pensil untuk koreksi, Grip Area sebagai bagian pegangan yang nyaman dan ergonomis, Side Switch (Tombol Samping) yang dapat diprogram untuk fungsi tambahan seperti klik kanan atau perintah khusus, dan Replaceable Nib (Ujung Pena) yang bisa diganti ketika sudah aus. Pena harus dipegang seperti memegang pulpen biasa dengan posisi jari yang nyaman agar tombol samping mudah dijangkau. Posisi pena dapat dimiringkan untuk kenyamanan menggambar. Untuk menghapus, balik pena dan gunakan bagian eraser.', 'wacom,pro pen,stylus,pena digital', 'general', 0, NULL, '2026-02-05 10:08:08', '2026-02-05 03:08:08'),
(386, 'Troubleshooting Tekanan Pen Wacom', 'Jika tekanan pena Wacom tidak berfungsi atau tidak terdeteksi saat menggambar, lakukan langkah berikut: Pertama, pastikan driver Wacom sudah terinstal dengan benar dan diperbarui ke versi terbaru dengan mengecek di Wacom Desktop Center atau mengunjungi website resmi Wacom. Periksa pengaturan tekanan pena di Wacom Desktop Center dengan membuka menu Pen settings dan pastikan pressure sensitivity diaktifkan serta kurva tekanan sesuai preferensi. Tutup dan buka kembali aplikasi desain yang digunakan (seperti Photoshop, Illustrator, Clip Studio Paint) karena kadang aplikasi perlu di-restart agar mengenali pengaturan tekanan. Periksa kondisi ujung pena (nib), jika sudah aus segera ganti dengan yang baru. Lakukan kalibrasi pena melalui Wacom Desktop Center jika diperlukan.', 'wacom,troubleshooting,tekanan pen,pressure', 'general', 0, NULL, '2026-02-05 10:08:08', '2026-02-05 03:08:08'),
(387, 'Troubleshooting Side Switch Pen Wacom', 'Jika tombol samping (Side Switch) pada Wacom Pro Pen tidak berfungsi, lakukan konfigurasi berikut: Buka Wacom Desktop Center di komputer dan pilih menu pengaturan untuk pena. Periksa pengaturan Side Switch dengan mengklik pada tombol yang ingin dikonfigurasi. Pastikan fungsi tombol sudah ditetapkan dengan benar sesuai kebutuhan, misalnya untuk Klik Kanan, Pan, Eraser, atau fungsi kustom lainnya. Setiap tombol samping dapat dikonfigurasi secara independen untuk fungsi yang berbeda. Simpan pengaturan dengan mengklik Apply atau OK, kemudian uji kembali tombol dengan menggunakan pena di aplikasi desain. Jika masih tidak berfungsi, restart aplikasi dan Wacom Desktop Center.', 'wacom,troubleshooting,side switch', 'general', 0, NULL, '2026-02-05 10:08:08', '2026-02-05 03:08:08'),
(388, 'Troubleshooting Nib Pen Wacom', 'Jika ujung pena (nib) Wacom tidak berfungsi dengan baik atau respon tidak akurat, lakukan perawatan berikut: Periksa kondisi ujung pena secara rutin, jika terlihat aus, pendek, atau tidak merata segera ganti nib dengan yang baru menggunakan nib remover tool atau pinset. Pastikan permukaan tablet (Active Area) selalu bersih dari debu, kotoran, atau sisa tinta yang bisa mengganggu kinerja pena dan sensitivitas. Bersihkan permukaan dengan kain mikrofiber lembut. Gunakan nib yang sesuai dengan jenis yang direkomendasikan oleh Wacom, tersedia berbagai jenis nib seperti standard, felt, flex, dan stroke untuk sensasi berbeda. Pasang nib dengan benar, pastikan terpasang kuat dan tidak goyang. Kalibrasi ulang pena jika diperlukan melalui Wacom Desktop Center.', 'wacom,troubleshooting,nib,ujung pen', 'general', 0, NULL, '2026-02-05 10:08:08', '2026-02-05 03:08:08'),
(389, 'Perawatan Wacom Pro Pen', 'Untuk merawat Wacom Pro Pen, saat tidak digunakan simpan pena pada pen stand yang disediakan atau letakkan rata di meja dengan posisi aman. Jangan menyimpan pena dengan posisi ujung (nib) menyentuh permukaan keras karena dapat menyebabkan nib cepat aus atau bengkok. Jangan meninggalkan pena di atas tablet Active Area dalam waktu lama karena dapat mengganggu kursor dan membuat mouse tidak bisa digunakan. Hindari menjatuhkan pena dari ketinggian karena komponen internal sensitif dapat rusak. Ganti nib secara berkala sebelum terlalu aus untuk menjaga akurasi dan respons tetap optimal. Bersihkan grip area secara berkala dari keringat atau kotoran. Simpan pena di tempat yang kering dan terhindar dari suhu ekstrem.', 'wacom,pro pen,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:08:08', '2026-02-05 03:08:08'),
(390, 'Steam Press', 'Steam Press adalah mesin press panas yang berfungsi untuk menyetrika dan merapikan bahan kain menggunakan kombinasi panas dan uap untuk hasil yang rapi dan profesional. Mesin ini bekerja dengan memberikan tekanan merata pada permukaan kain sambil mengalirkan uap, sehingga lipatan dan kerutan dapat hilang dengan cepat tanpa merusak serat kain. Steam press memiliki dua plat utama: Plat Atas sebagai sumber panas dan pemberi tekanan, serta Plat Bawah sebagai alas tempat kain diletakkan untuk menjaga kain tetap stabil. Dilengkapi dengan Panel Kontrol untuk mengatur suhu, lama waktu press, dan jumlah uap yang keluar, disesuaikan dengan jenis dan ketebalan bahan kain. Penggunaan steam press lebih praktis dan efisien dibanding setrika manual karena menekan seluruh bagian kain sekaligus.', 'steam press,setrika,press,tekstil', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(391, 'Cara Menggunakan Steam Press', 'Untuk menggunakan mesin Steam Press, ikuti langkah berikut: Pertama, hubungkan mesin steam press ke sumber listrik dengan memastikan kabel power terpasang dengan baik. Isi tangki air dengan air bersih untuk menghasilkan uap, perhatikan batas maksimal pengisian air. Atur suhu pada panel kontrol sesuai jenis kain yang akan di-press (kain tipis memerlukan suhu lebih rendah, kain tebal memerlukan suhu lebih tinggi). Atur waktu press sesuai kebutuhan, biasanya berkisar 10-30 detik tergantung ketebalan kain. Tunggu hingga mesin mencapai suhu kerja yang ditandai dengan indikator siap. Letakkan kain pada plat bawah dengan posisi rata dan tidak berlipat. Turunkan plat atas dengan menekan handle atau tombol press, berikan tekanan merata. Tunggu hingga waktu selesai atau alarm berbunyi. Angkat plat atas dengan hati-hati dan ambil kain yang sudah rapi.', 'steam press,cara menggunakan,press kain', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(392, 'Troubleshooting Steam Press Tidak Menyala', 'Jika mesin Steam Press tidak menyala, lakukan pemeriksaan berikut: Pertama, pastikan kabel power terhubung dengan benar ke sumber listrik, periksa sambungan di mesin dan di stop kontak. Periksa stop kontak apakah aliran listrik aktif dengan mencoba menyalakan perangkat lain atau gunakan stop kontak yang berbeda. Tekan tombol ON/Power pada mesin press dengan tegas, pastikan tombol benar-benar ditekan. Periksa apakah ada sekering atau circuit breaker yang terputus. Gunakan kabel power lain jika tersedia untuk memastikan bukan masalah pada kabel. Jika mesin masih tidak menyala setelah semua pengecekan, hubungi teknisi atau service center resmi.', 'steam press,troubleshooting,tidak menyala', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(393, 'Troubleshooting Steam Press Tidak Panas', 'Jika mesin Steam Press tidak panas atau suhu tidak mencapai target yang diatur, lakukan langkah berikut: Periksa pengaturan suhu pada panel kontrol, pastikan suhu sudah diatur dengan benar dan tidak dalam mode standby. Pastikan mesin sudah dinyalakan beberapa menit (biasanya 5-10 menit) hingga mencapai suhu kerja yang diinginkan, indikator ready akan menyala jika suhu sudah tercapai. Periksa indikator pemanas apakah menyala, jika tidak menyala kemungkinan ada masalah pada elemen pemanas. Matikan mesin dan biarkan dingin jika suhu tidak naik setelah waktu yang cukup. Periksa apakah ada error code atau pesan error pada display panel. Hubungi teknisi apabila elemen pemanas bermasalah atau memerlukan penggantian komponen.', 'steam press,troubleshooting,tidak panas', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(394, 'Troubleshooting Timer Steam Press', 'Jika timer Steam Press tidak berfungsi atau alarm tidak berbunyi, lakukan langkah berikut: Periksa pengaturan waktu (timer) pada panel kontrol, pastikan waktu sudah diatur dengan benar dan tidak dalam posisi nol. Pastikan tombol Start atau Press sudah ditekan setelah mengatur waktu, karena timer tidak akan berjalan jika proses press belum dimulai. Ulangi pengaturan timer dari awal, matikan mesin terlebih dahulu kemudian nyalakan kembali dan atur ulang waktu. Periksa volume alarm atau buzzer, mungkin sudah diatur terlalu rendah atau dimatikan. Matikan dan nyalakan kembali mesin jika timer tidak berjalan meskipun sudah diatur dengan benar. Laporkan ke teknisi jika alarm tetap tidak berfungsi atau ada kerusakan pada sistem timer elektronik.', 'steam press,troubleshooting,timer', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(395, 'Perawatan Steam Press', 'Untuk merawat Steam Press, selalu matikan mesin setelah selesai digunakan untuk menghemat energi dan mencegah overheating. Kosongkan tangki air jika mesin tidak akan digunakan dalam waktu lama untuk mencegah kerak atau jamur terbentuk di dalam tangki, gunakan air bersih atau air suling untuk hasil terbaik. Bersihkan plat atas dan bawah secara berkala dari sisa kain, kotoran, atau kerak menggunakan kain lembut dan pembersih khusus, lakukan pembersihan saat plat sudah dingin. Hindari menyentuh plat saat panas untuk mencegah luka bakar. Periksa selang uap secara berkala dan bersihkan jika ada penyumbatan. Lakukan descaling (pembersihan kerak) secara rutin sesuai instruksi manual. Simpan mesin di tempat yang kering dan terhindar dari kelembaban berlebih.', 'steam press,perawatan,maintenance', 'general', 0, NULL, '2026-02-05 10:08:40', '2026-02-05 03:08:40'),
(396, 'Mesin Heat Press', 'Mesin Heat Press adalah mesin press panas yang digunakan untuk memindahkan desain ke media seperti kaos, kain, tas, topi, atau bahan datar lainnya menggunakan kombinasi panas dan tekanan. Mesin ini terdiri dari Plat Atas (Plat Pemanas) sebagai sumber panas utama yang memanaskan hingga suhu yang diatur dan menekan desain dengan tekanan merata, sehingga hasil transfer rapi, presisi, dan tahan lama. Plat Bawah (Meja Press) berfungsi sebagai permukaan untuk meletakkan media agar tetap rata dan stabil selama proses pressing. Tuas/Handle Press digunakan untuk menurunkan dan menaikkan plat pemanas serta memberikan tekanan merata. Panel Kontrol Digital berfungsi untuk mengatur suhu (biasanya 150-200°C) dan waktu pemanasan (10-30 detik) sesuai jenis media. Tombol Power untuk menyalakan dan mematikan mesin.', 'heat press,press panas,transfer,printing', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(397, 'Cara Menggunakan Heat Press', 'Untuk menggunakan Mesin Heat Press, ikuti langkah berikut: Pertama, pastikan mesin heat press sudah terhubung dengan baik ke sumber listrik dengan menyolokkan kabel power ke stop kontak yang stabil. Nyalakan mesin dengan menekan tombol ON dan tunggu beberapa saat hingga mesin siap digunakan. Atur suhu sesuai jenis bahan pada panel kontrol, umumnya 150-180°C untuk kaos katun, suhu lebih rendah untuk bahan sintetis. Atur waktu press sesuai kebutuhan, umumnya 10-20 detik tergantung jenis transfer dan bahan. Tunggu hingga mesin mencapai suhu yang ditentukan, indikator ready akan menyala. Letakkan media (kaos/kain) di atas plat bawah dengan posisi rata. Letakkan desain transfer (transfer paper, vinyl, sublimasi) di posisi yang diinginkan pada media. Turunkan tuas hingga plat atas menekan media dengan tekanan penuh. Tunggu hingga waktu habis atau alarm berbunyi. Angkat tuas kembali dengan hati-hati dan lepaskan transfer paper jika diperlukan (hot peel atau cold peel tergantung jenis).', 'heat press,cara menggunakan,transfer printing', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(398, 'Troubleshooting Heat Press Tidak Menyala', 'Jika Mesin Heat Press tidak menyala, lakukan pemeriksaan berikut: Pertama, pastikan kabel power terhubung dengan benar ke sumber listrik, periksa sambungan di mesin dan di stop kontak tidak longgar. Periksa stop kontak apakah aktif dengan mencoba perangkat lain atau pindah ke stop kontak yang berbeda. Tekan tombol ON pada mesin dengan tegas dan pastikan tombol benar-benar dalam posisi ON. Periksa apakah ada sekering (fuse) yang putus di dalam mesin atau panel listrik. Ganti kabel power atau stop kontak lain jika masih tidak menyala untuk memastikan bukan masalah pada kabel atau sumber listrik. Periksa circuit breaker atau MCB di panel listrik mungkin terputus. Jika semua sudah dicek namun mesin tetap tidak menyala, hubungi teknisi atau service center.', 'heat press,troubleshooting,tidak menyala', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(399, 'Troubleshooting Heat Press Tidak Panas', 'Jika Mesin Heat Press tidak panas atau suhu tidak mencapai target, lakukan langkah berikut: Periksa pengaturan suhu pada panel kontrol, pastikan suhu sudah diatur dengan nilai yang sesuai (tidak nol) dan mode heating aktif. Pastikan mesin sudah dinyalakan beberapa saat (5-15 menit) untuk mencapai suhu kerja yang diinginkan, elemen pemanas memerlukan waktu untuk panas. Periksa apakah indikator heating menyala pada display panel, jika tidak menyala kemungkinan ada masalah pada sensor atau elemen pemanas. Jika tetap tidak panas setelah waktu yang cukup, matikan mesin dan periksa apakah ada kabel internal yang lepas atau elemen pemanas rusak. Gunakan termometer infrared untuk mengecek suhu aktual plat pemanas. Hubungi teknisi jika masalah berlanjut karena mungkin memerlukan penggantian elemen pemanas atau thermostat.', 'heat press,troubleshooting,tidak panas,suhu', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(400, 'Troubleshooting Waktu Press Heat Press', 'Jika waktu press Heat Press tidak berfungsi atau alarm tidak berbunyi, lakukan langkah berikut: Periksa pengaturan timer di panel kontrol, pastikan waktu sudah diatur dengan nilai yang sesuai (tidak nol). Pastikan tombol start atau handle press sudah ditekan/diturunkan setelah pengaturan selesai, karena timer biasanya dimulai saat plat mulai menekan. Periksa apakah ada mode auto timer atau manual timer yang perlu diaktifkan. Periksa volume buzzer/alarm, mungkin sudah diatur terlalu rendah atau mati. Matikan dan nyalakan kembali mesin jika timer tidak berjalan meskipun sudah diatur dengan benar, restart sistem elektronik. Reset pengaturan timer ke default dan atur ulang. Jika timer tetap tidak berfungsi, kemungkinan ada masalah pada modul timer elektronik dan perlu pengecekan teknisi.', 'heat press,troubleshooting,timer,alarm', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(401, 'Troubleshooting Plat Heat Press', 'Jika plat Mesin Heat Press tidak menekan media dengan kuat atau tekanan tidak merata, lakukan pemeriksaan berikut: Periksa tuas/handle apakah terkunci dengan benar dalam posisi press, handle harus ditekan hingga mentok dan terkunci. Pastikan media dan desain ditempatkan dengan benar di tengah plat bawah, tidak miring atau terlipat. Sesuaikan tekanan tuas sesuai jenis bahan, beberapa mesin heat press memiliki adjustment knob untuk mengatur tingkat tekanan, putar searah jarum jam untuk menambah tekanan. Periksa apakah ada bantalan pressing pad yang sudah kempes atau rusak, ganti jika perlu. Pastikan plat atas dan bawah sejajar dan tidak miring. Periksa spring atau pegas pada mekanisme handle mungkin sudah lemah. Jika menggunakan plat attachment (untuk topi, piring, dll), pastikan terpasang dengan benar.', 'heat press,troubleshooting,plat,tekanan', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(402, 'Perawatan Heat Press', 'Untuk merawat Mesin Heat Press dengan baik, ikuti panduan berikut: Jangan menyentuh plat pemanas saat mesin menyala atau baru dimatikan karena suhu bisa mencapai 200°C dan menyebabkan luka bakar serius. Gunakan sarung tangan tahan panas atau heat gloves jika diperlukan saat mengganti plat atau membersihkan area panas. Jauhkan mesin dari air, cairan, dan bahan mudah terbakar seperti kertas, kain tipis, atau bahan kimia. Jangan meninggalkan mesin dalam kondisi menyala tanpa pengawasan untuk mencegah kebakaran atau kecelakaan. Matikan mesin setelah selesai digunakan dan cabut dari sumber listrik. Bersihkan plat pemanas secara berkala dari sisa transfer atau lem menggunakan pembersih khusus saat plat sudah dingin. Periksa kabel power secara rutin dari kerusakan. Lakukan kalibrasi suhu secara berkala menggunakan termometer infrared. Simpan di tempat yang kering dan aman.', 'heat press,perawatan,keselamatan,maintenance', 'general', 0, NULL, '2026-02-05 10:08:45', '2026-02-05 03:08:45'),
(403, 'Mesin DTG', 'Mesin DTG (Direct to Garment) adalah mesin cetak digital tekstil yang diproduksi oleh brand seperti Epson, Brother, Kornit, atau Ricoh. Mesin ini mencetak desain digital langsung ke kaos katun atau kain dengan tinta khusus berbasis air, menghasilkan warna akurat dan detail tinggi tanpa perlu screen manual seperti sablon. Komponen utama meliputi: Sistem Tinta (CMYK + White) yang menyalurkan tinta dari tabung ke print head, White Ink System dengan pengaduk untuk mencetak tinta putih sebagai dasar pada kain gelap, Platen (Meja Kaos) untuk meletakkan dan meratakan kaos, Carriage yang membawa print head, Motor dan Rail System untuk pergerakan presisi, Control Panel/RIP Software untuk mengatur desain dan proses cetak, serta Heater/Heat Press untuk mengeringkan dan mengunci tinta. Mesin DTG cocok untuk produksi custom satuan atau dalam jumlah kecil hingga menengah dengan detail tinggi.', 'dtg,direct to garment,printing,tekstil', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08');
INSERT INTO `knowledge_base` (`id`, `keyword`, `description`, `tags`, `category`, `usage_count`, `last_used`, `created_at`, `updated_at`) VALUES
(404, 'Peralatan DTG', 'Untuk mengoperasikan Mesin DTG, diperlukan beberapa peralatan pendukung: Mesin DTG sebagai alat utama untuk mencetak desain digital langsung ke kain. Komputer dengan software RIP (Raster Image Processor) untuk mengatur, memodifikasi, dan menyiapkan desain sebelum dicetak. Tinta DTG CMYK (Cyan, Magenta, Yellow, Black) dan White untuk memberikan warna pada hasil cetak dengan jelas dan akurat. Kaos atau kain berbahan katun sebagai media utama pencetakan (katun 100% memberikan hasil terbaik). Cairan Pretreatment untuk disemprotkan pada kaos sebelum cetak guna meningkatkan daya serap tinta putih dan membuat cetakan lebih jelas, rapi, dan tahan lama. Heat Press untuk mengeringkan tinta hasil cetak DTG secara merata dan mengunci desain pada kain agar tahan lama dan tidak mudah luntur saat dicuci.', 'dtg,peralatan,tinta,pretreatment', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(405, 'Cara Menggunakan Mesin DTG', 'Untuk menggunakan Mesin DTG, ikuti langkah lengkap berikut: PERSIAPAN ALAT - Pastikan mesin DTG dalam kondisi bersih dari sisa tinta atau kotoran. Hubungkan mesin DTG ke komputer dengan kabel USB atau jaringan WiFi. Nyalakan mesin DTG dan tunggu hingga proses booting dan initialization selesai. Periksa level tinta untuk semua warna (CMYK dan White) pastikan cukup untuk mencegah hasil cetak tidak sempurna. Lakukan nozzle check dan head cleaning jika diperlukan. PERSIAPAN BAHAN - Pilih kaos berbahan katun 100% yang bersih dan sudah dicuci untuk menghilangkan sizing (lapisan pabrik). Semprotkan cairan pretreatment secara merata pada area yang akan dicetak menggunakan spray gun atau aplikator. Jangan terlalu basah atau terlalu kering. Keringkan kaos yang sudah diberi pretreatment menggunakan heat press pada suhu 150-170°C selama 30-45 detik hingga benar-benar kering dan siap cetak. PROSES PENCETAKAN - Letakkan kaos di meja/platen mesin DTG dengan posisi yang stabil dan kencangkan dengan hoop ring. Atur kaos agar rata, tidak ada lipatan atau gelembung udara untuk hasil cetak yang sempurna. Buka software RIP di komputer, import desain, atur ukuran, posisi, dan warna sesuai kebutuhan. Lakukan test print jika perlu. Jalankan perintah print dari software untuk memulai pencetakan desain, mesin akan mulai menyemprotkan tinta ke kaos. Tunggu hingga proses pencetakan selesai (biasanya 2-5 menit tergantung ukuran dan kompleksitas desain), jangan menggerakkan platen. FINISHING - Angkat kaos dari platen dengan hati-hati setelah proses cetak selesai. Pre-press kaos sebentar dengan heat press untuk mengurangi kelembaban tinta. Keringkan hasil cetak pada kaos menggunakan heat press pada suhu 160-180°C selama 30-60 detik dengan tekanan medium, gunakan teflon sheet atau parchment paper untuk melindungi. Angkat kaos setelah dingin, biarkan mengering sempurna selama 24 jam sebelum dicuci pertama kali. Cetakan sudah siap digunakan atau dikemas.', 'dtg,cara menggunakan,printing process', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(406, 'Troubleshooting DTG Tidak Menyala', 'Jika Mesin DTG tidak menyala, lakukan pemeriksaan menyeluruh berikut: Periksa sambungan listrik dan pastikan kabel power terhubung dengan benar ke mesin dan ke sumber listrik, pastikan tidak ada kabel yang longgar atau rusak. Periksa stop kontak apakah aktif dengan mencoba perangkat lain atau gunakan stop kontak berbeda yang sudah terbukti berfungsi. Pastikan tombol power mesin ditekan dengan benar, beberapa mesin memiliki power switch di dua tempat (belakang dan depan). Periksa sekering atau circuit breaker di panel mesin, ganti jika putus. Periksa voltage input apakah sesuai dengan spesifikasi mesin (220V atau 110V). Ganti kabel power atau stop kontak lain jika masalah tetap muncul untuk memastikan bukan masalah pada kabel. Periksa apakah ada indikator error pada display panel. Jika mesin tetap tidak menyala setelah semua pengecekan, hubungi teknisi resmi atau distributor mesin untuk service lebih lanjut.', 'dtg,troubleshooting,tidak menyala,power', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(407, 'Troubleshooting DTG Bunyi Aneh', 'Jika Mesin DTG mengeluarkan bunyi aneh atau carriage macet, lakukan troubleshooting berikut: Matikan mesin segera dan cabut dari sumber listrik, biarkan dingin sebentar (5-10 menit) untuk keamanan. Periksa jalur rail system dan motor, pastikan bebas dari debu, kotoran, serat kain, atau serpihan yang dapat menghalangi pergerakan. Gunakan vacuum cleaner atau kuas halus untuk membersihkan. Periksa carriage belt apakah masih kencang atau sudah kendor, jika kendor perlu dikencangkan sesuai manual. Lumasi rail dengan pelumas khusus printer (light machine oil atau white lithium grease) secara tipis dan merata, jangan berlebihan. Periksa bearing atau roda pada carriage apakah masih berputar lancar atau sudah aus. Periksa kabel print head apakah tertekuk atau terjepit yang dapat menghambat pergerakan. Restart mesin setelah pemeriksaan dan pembersihan, lakukan test print untuk memastikan pergerakan sudah smooth. Jika bunyi masih ada atau carriage tetap macet, hubungi teknisi untuk pengecekan motor atau komponen mekanis lain.', 'dtg,troubleshooting,carriage,bunyi', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(408, 'Troubleshooting Nozzle DTG', 'Jika nozzle Mesin DTG tersumbat atau cleaning system tidak berfungsi, lakukan langkah berikut: Jalankan prosedur cleaning cycle melalui software RIP atau control panel mesin untuk membersihkan print head, lakukan 2-3 kali cleaning cycle jika perlu. Lakukan nozzle check setelah setiap cleaning untuk melihat perbaikan pola. Periksa level tinta dan pastikan tinta tidak mengental atau kering, tinta DTG yang terlalu lama tersimpan atau jarang digunakan dapat mengental dan menyumbat nozzle. Ganti dengan tinta fresh jika perlu. Periksa white ink circulation system, pastikan white ink agitator berfungsi karena tinta putih mudah mengendap. Lakukan manual cleaning dengan cleaning solution khusus untuk print head DTG sesuai manual, biasanya dengan merendam print head dalam cleaning solution. Pastikan capping station (tempat parkir print head) berfungsi dengan baik dan tidak bocor. Periksa tinta damper apakah ada gelembung udara, keluarkan udara jika ada. Jika masalah berlanjut setelah semua langkah, mungkin print head perlu diganti atau dibawa ke service center untuk deep clean profesional. Lakukan preventive maintenance rutin untuk mencegah clogging.', 'dtg,troubleshooting,nozzle,clogging', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(409, 'Perawatan Mesin DTG', 'Untuk merawat Mesin DTG agar tetap optimal, lakukan perawatan rutin berikut: Bersihkan print head setiap selesai digunakan dengan menjalankan cleaning cycle minimal 1-2 kali, terutama jika tidak akan digunakan dalam beberapa hari. Lakukan nozzle check setiap hari sebelum produksi untuk memastikan semua nozzle firing dengan baik. Tutup mesin dengan dust cover setelah pemakaian untuk melindungi dari debu yang dapat menyumbat nozzle. Gunakan tinta sesuai rekomendasi pabrik, jangan mencampur brand tinta yang berbeda karena dapat merusak print head. Gunakan tinta dengan expired date yang masih valid. Lakukan maintenance rutin mingguan meliputi: pembersihan wiper blade, capping station, dan platen dari sisa tinta atau pretreatment. Jalankan white ink circulation system setiap hari untuk mencegah tinta putih mengendap. Lakukan head cleaning manual sebulan sekali dengan cleaning solution. Kalibrasi head alignment setiap bulan atau jika hasil cetak mulai blur. Simpan di ruangan ber-AC (18-25°C) dengan humidity terkontrol (40-60%). Update firmware dan software RIP secara berkala. Catat log maintenance untuk tracking. Jika mesin tidak digunakan lebih dari seminggu, lakukan power nozzle wash. Lakukan service teknisi setiap 6 bulan atau sesuai rekomendasi pabrikan.', 'dtg,perawatan,maintenance,preventive', 'general', 0, NULL, '2026-02-05 10:09:08', '2026-02-05 03:09:08'),
(410, 'Komputer PC Windows', 'Komputer PC Windows adalah perangkat komputasi yang digunakan untuk menjalankan sistem operasi Windows dan berbagai aplikasi kerja. Komponen utama sistem terdiri dari Unit CPU yang berfungsi sebagai pusat pemrosesan data dan pengendali seluruh sistem komputer, tempat komponen seperti prosesor, motherboard, RAM, dan penyimpanan bekerja untuk menjalankan perintah dan mengolah data. Monitor PC untuk menampilkan tampilan visual dari sistem Windows sehingga pengguna dapat melihat desktop, ikon, jendela aplikasi, dan informasi yang sedang dijalankan. Keyboard sebagai perangkat input untuk mengetik dengan berbagai tombol fungsi (F1-F12, Esc) yang memiliki fungsi khusus. Mouse sebagai perangkat input untuk menggerakkan kursor dengan Left Click untuk memilih, Right Click untuk menu tambahan, dan Scroll Wheel untuk menggulir tampilan.', 'pc,windows,komputer,desktop,computer', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-09 03:52:51'),
(411, 'Port PC Windows', 'PC Windows memiliki berbagai port koneksi di bagian belakang CPU untuk menghubungkan perangkat eksternal: Power Cable untuk menyalurkan daya listrik dari stop kontak agar komputer dapat menyala dan beroperasi normal. USB Type-A sebagai port paling umum untuk menghubungkan perangkat seperti mouse, keyboard, flashdisk, printer, dan perangkat USB lainnya. Ethernet (LAN) untuk menghubungkan komputer ke jaringan internet atau lokal melalui kabel LAN dengan koneksi lebih stabil dan cepat dibanding WiFi. VGA Port untuk menampilkan gambar ke monitor dengan sinyal analog (umumnya pada perangkat lama). Audio Port untuk menghubungkan headset, speaker, atau mikrofon ke komputer. DisplayPort/DVI untuk menghubungkan ke monitor dengan kualitas video lebih baik dan mendukung resolusi tinggi pada monitor modern atau profesional. HDMI Cable untuk menghubungkan ke monitor, TV, atau proyektor dengan satu kabel yang mengirimkan sinyal video dan audio sekaligus dengan kualitas digital.', 'pc,port,koneksi,usb,hdmi,vga', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(412, 'Port Monitor Windows', 'Monitor Windows memiliki beberapa port koneksi di bagian belakang: AC Input sebagai sumber listrik untuk monitor. HDMI Port untuk menerima sinyal video dan audio digital dari komputer/laptop ke monitor dengan kualitas tinggi. DVI/Display Port untuk menerima sinyal video digital dari komputer ke monitor dengan kualitas tajam. VGA Port untuk menerima sinyal video analog dari komputer ke monitor (untuk monitor lama). Audio Out untuk mengeluarkan suara dari monitor ke perangkat audio eksternal seperti speaker atau headphone. Audio In untuk menerima sinyal suara dari komputer ke monitor jika monitor memiliki speaker built-in.', 'monitor,port,display,hdmi,vga', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(413, 'Fungsi Tombol Keyboard PC', 'Keyboard PC Windows memiliki berbagai tombol dengan fungsi khusus: Esc (Escape) untuk membatalkan perintah yang sedang berjalan serta keluar dari menu popup, dialog box, atau mode tertentu. F1 untuk membuka menu bantuan (Help) pada aplikasi atau sistem operasi. F2 untuk mengganti nama (Rename) file atau folder yang dipilih. F3 untuk membuka fitur pencarian (Search) pada file explorer. F4 digunakan bersama Alt+F4 untuk menutup aplikasi yang sedang aktif. F5 untuk melakukan refresh atau memuat ulang halaman pada browser atau file explorer. F6 untuk memindahkan fokus kursor antar elemen atau panel. F7 untuk pemeriksaan ejaan dan tata bahasa pada Microsoft Word. F8 untuk membantu seleksi teks dan fungsi boot saat komputer dinyalakan. F9 untuk memperbarui data dan field tertentu pada dokumen. F10 untuk mengaktifkan menu bar pada aplikasi agar dapat diakses via keyboard. F11 untuk mengaktifkan atau keluar dari mode layar penuh (Full Screen) pada browser. F12 untuk membuka menu Save As pada Microsoft Word serta Developer Tools pada browser.', 'keyboard,tombol fungsi,shortcut,windows', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(414, 'Cara Menyalakan PC Windows', 'Untuk menyalakan Komputer PC Windows, ikuti langkah berikut: Pertama, pastikan komputer dalam kondisi mati, kemudian hubungkan kabel USB mouse dan keyboard ke port USB CPU, sambungkan kabel HDMI atau VGA dari CPU ke monitor sesuai port yang tersedia, dan colokkan kabel power CPU ke sumber listrik (stop kontak) dengan benar dan kuat. Tekan tombol Power pada unit CPU yang biasanya terletak di bagian depan atau atas casing, tunggu hingga lampu indikator CPU menyala menandakan komputer mulai booting. Monitor akan menyala dan menampilkan logo Windows, tunggu hingga proses booting selesai (biasanya 30-60 detik tergantung spesifikasi). Pada layar login Windows, pilih akun pengguna yang akan digunakan, masukkan kata sandi (password) jika diminta dengan memperhatikan huruf besar/kecil, kemudian tekan tombol Enter atau klik tombol Sign In. Setelah berhasil login dan masuk ke tampilan desktop Windows, komputer siap digunakan untuk berbagai aktivitas kerja, pembelajaran, atau hiburan. Pengguna dapat menjalankan aplikasi sesuai kebutuhan dengan mengklik menu Start atau ikon aplikasi di desktop.', 'pc,menyalakan,booting,login,windows,menggunakan,computer', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-09 03:53:14'),
(415, 'Mengatur Kecerahan Layar Windows', 'Untuk mengatur kecerahan layar di PC Windows, ikuti langkah berikut: Klik ikon Settings pada menu Start atau tekan kombinasi tombol Windows + I pada keyboard untuk membuka menu pengaturan Windows dengan cepat. Setelah menu Settings terbuka, pilih menu System untuk mengakses berbagai pengaturan sistem komputer. Pada menu System, pilih submenu Display untuk membuka pengaturan tampilan layar secara lengkap. Cari bagian Brightness and Color pada halaman Display yang berisi kontrol kecerahan. Geser slider \"Change brightness for the built-in display\" ke kanan untuk menambah kecerahan layar agar lebih terang, atau geser slider ke kiri untuk mengurangi kecerahan layar sesuai kebutuhan dan kenyamanan pengguna. Atur tingkat kecerahan layar agar nyaman di mata dan tidak terlalu terang (menyilaukan) atau terlalu gelap (sulit melihat). Pengaturan kecerahan yang tepat sangat penting untuk membantu mengurangi kelelahan mata (eye strain) saat menggunakan komputer dalam waktu lama. Setelah selesai mengatur, pengaturan akan tersimpan secara otomatis tanpa perlu menekan tombol simpan, dan akan diterapkan langsung pada layar.', 'windows,kecerahan,brightness,display,settings', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(416, 'Koneksi Internet PC Windows Tel-U', 'Untuk menghubungkan PC Windows ke internet jaringan Tel-U, ikuti langkah berikut: Klik ikon Network yang berbentuk WiFi atau Ethernet pada pojok kanan bawah layar Windows (system tray) untuk membuka menu pengaturan jaringan yang tersedia. Dari daftar jaringan nirkabel yang muncul pada layar, pilih jaringan Wi-Fi dengan nama \"Tel-U\" atau \"Tel-U Connect\" yang merupakan jaringan resmi Universitas Telkom. Setelah memilih jaringan, akan muncul halaman login atau authentication page. Masukkan username dan password pada kolom yang disediakan sesuai dengan akun yang telah diberikan (biasanya menggunakan NIM untuk mahasiswa atau NIP untuk dosen/staff). Klik tombol Login atau Connect, kemudian tunggu beberapa saat (5-15 detik) hingga proses autentikasi jaringan selesai dan sistem memvalidasi kredensial yang dimasukkan. Pastikan status koneksi pada icon network berubah menjadi \"Connected\" dengan tanda internet aktif sebagai tanda bahwa komputer telah berhasil terhubung ke jaringan internet Tel-U dan siap digunakan untuk browsing, download, atau aktivitas online lainnya. Jika gagal terhubung, periksa kembali username dan password atau hubungi helpdesk IT.', 'windows,internet,wifi,tel-u,koneksi', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(417, 'Membuka dan Menutup Aplikasi Windows', 'Untuk membuka aplikasi di PC Windows, klik menu Start (logo Windows) di pojok kiri bawah layar atau tekan tombol Windows pada keyboard untuk menampilkan daftar program yang tersedia. Alternatif lainnya, klik langsung pada ikon aplikasi yang ada di desktop atau taskbar jika aplikasi sudah di-pin. Pilih dan klik aplikasi yang akan digunakan sesuai dengan kebutuhan pekerjaan (misalnya Microsoft Word, Excel, browser, dll). Tunggu beberapa saat hingga aplikasi terbuka sepenuhnya dan jendela aplikasi muncul di layar, siap digunakan untuk menjalankan aktivitas kerja atau pembelajaran. Loading time bervariasi tergantung spesifikasi komputer dan ukuran aplikasi. Untuk menutup aplikasi yang sedang berjalan, klik tombol Close yang berbentuk X (silang) di pojok kanan atas jendela aplikasi untuk mengakhiri penggunaan aplikasi tersebut dengan aman. Alternatif lain adalah menggunakan shortcut Alt+F4 saat aplikasi aktif. Pastikan aplikasi telah tertutup dengan sempurna dan tidak lagi aktif di background (cek di Task Manager jika perlu) sebelum membuka atau menjalankan aplikasi lain yang berat, sehingga sistem komputer tetap berjalan dengan lancar, stabil, dan tidak terjadi lag atau freeze akibat terlalu banyak aplikasi berjalan bersamaan.', 'windows,aplikasi,membuka,menutup,start menu', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(418, 'Cara Shutdown PC Windows', 'Untuk mematikan Komputer PC Windows dengan benar dan aman, ikuti prosedur shutdown yang tepat: Klik tombol Start (logo Windows) yang terletak di pojok kiri bawah layar untuk membuka start menu. Pada menu yang muncul, cari dan pilih menu Power yang biasanya ditandai dengan icon power atau terletak di bagian bawah menu start. Setelah mengklik Power, akan muncul beberapa opsi seperti Sleep, Restart, dan Shut Down. Klik opsi \"Shut Down\" untuk mematikan komputer sepenuhnya. Sistem akan mulai menutup semua aplikasi yang berjalan, menyimpan pengaturan sistem, dan mempersiapkan komputer untuk dimatikan. Tunggu hingga layar monitor mati sepenuhnya dan unit CPU berhenti beroperasi yang ditandai dengan lampu indikator mati dan suara kipas berhenti. Proses shutdown biasanya memerlukan waktu 10-30 detik tergantung spesifikasi dan jumlah aplikasi yang berjalan. Jangan pernah mematikan komputer dengan mencabut kabel power secara paksa atau menekan tombol power lama karena dapat menyebabkan kerusakan sistem, corrupt data, atau kehilangan file yang belum tersimpan. Selalu gunakan prosedur shutdown yang benar untuk menjaga kesehatan hardware dan software komputer.', 'windows,shutdown,mematikan,power', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(419, 'Troubleshooting PC Windows Tidak Menyala', 'Jika Komputer PC Windows tidak menyala saat tombol power ditekan, lakukan troubleshooting berikut: Pertama, pastikan kabel power CPU terhubung dengan benar dan terpasang dengan kuat pada port daya di bagian belakang CPU, periksa tidak ada kabel yang longgar atau terlepas. Periksa sambungan kabel ke stop kontak listrik dan pastikan stop kontak dalam kondisi aktif dengan cara mencoba perangkat lain di stop kontak yang sama atau cek MCB/circuit breaker di panel listrik. Cek apakah stabilizer atau UPS (jika ada) dalam kondisi menyala dan berfungsi normal. Tekan tombol Power pada unit CPU dengan tegas, biasanya terletak di bagian depan atau atas casing. Tunggu beberapa detik (5-10 detik) hingga indikator daya atau lampu LED pada CPU menyala sebagai tanda komputer mulai beroperasi dan kipas mulai berputar. Perhatikan apakah ada bunyi beep dari motherboard yang mengindikasikan masalah hardware tertentu. Jika lampu indikator tidak menyala sama sekali dan tidak ada tanda-tanda kehidupan, periksa kabel power apakah rusak, coba gunakan kabel power lain yang sejenis. Periksa power supply unit (PSU) di dalam CPU mungkin rusak atau switch PSU dalam posisi OFF. Jika semua sudah dicek namun PC tetap tidak menyala, kemungkinan ada masalah hardware serius seperti PSU mati, motherboard rusak, atau komponen internal lainnya, segera hubungi teknisi IT untuk pengecekan lebih lanjut.', 'windows,troubleshooting,tidak menyala,power', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(420, 'Troubleshooting Monitor PC Tidak Menampilkan Gambar', 'Jika Monitor PC Windows tidak menampilkan gambar atau layar hitam (blank screen), lakukan troubleshooting berikut: Pertama, pastikan monitor dalam kondisi menyala dengan memeriksa lampu indikator power pada monitor aktif (biasanya LED biru atau hijau). Jika monitor mati, tekan tombol power monitor. Periksa kabel video VGA, HDMI, atau DisplayPort apakah sudah terhubung dengan kuat dan benar ke port CPU dan port monitor, pastikan tidak ada kabel yang longgar atau terlepas sebagian. Periksa apakah pin kabel tidak bengkok atau rusak terutama untuk VGA. Sesuaikan sumber input monitor (HDMI/VGA/DisplayPort/DVI) melalui tombol menu atau source pada monitor sesuai dengan jenis kabel yang digunakan untuk koneksi, karena monitor mungkin mendeteksi input yang salah. Jika monitor menampilkan pesan \"No Signal\", berarti monitor tidak menerima sinyal dari CPU. Pastikan CPU dalam keadaan menyala dengan memeriksa lampu indikator dan suara kipas. Jika layar masih kosong atau blank setelah pengecekan kabel, lakukan restart komputer dengan menekan tombol power CPU atau tombol reset untuk memuat ulang sistem tampilan dan driver grafis. Tunggu beberapa saat hingga proses booting selesai dan pastikan tampilan Windows muncul di layar monitor. Coba gunakan kabel video yang berbeda (misal dari VGA ganti ke HDMI) atau coba monitor di komputer lain untuk memastikan monitor berfungsi. Jika masalah berlanjut, kemungkinan ada masalah pada VGA card, driver display, atau monitor rusak, hubungi teknisi untuk pengecekan hardware.', 'windows,troubleshooting,monitor,no signal,blank screen', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(421, 'Troubleshooting Windows Tidak Bisa Booting', 'Jika Windows tidak bisa booting atau gagal masuk ke sistem operasi, lakukan langkah perbaikan berikut: Nyalakan komputer dengan menekan tombol Power pada CPU, lalu tunggu hingga sistem mencoba memuat Windows dan menampilkan logo atau loading screen. Jika Windows gagal masuk ke desktop atau terjebak di loading screen, sistem biasanya akan otomatis masuk ke menu \"Automatic Repair\" atau \"Windows Recovery Environment\" setelah beberapa kali gagal booting. Di menu Automatic Repair, akan muncul beberapa opsi perbaikan sistem. Pilih menu \"Startup Repair\" untuk melakukan perbaikan sistem secara otomatis yang akan mencoba memperbaiki file sistem yang corrupt atau konfigurasi boot yang bermasalah. Tunggu hingga proses perbaikan selesai, jangan mematikan komputer atau menekan tombol apapun selama proses berlangsung karena dapat memperburuk kondisi. Proses ini bisa memakan waktu 10-30 menit tergantung tingkat kerusakan. Setelah muncul pemberitahuan bahwa perbaikan selesai atau \"Repair completed\", klik tombol \"Restart\" atau \"Reboot\" untuk memulai ulang komputer dan mencoba boot kembali. Jika Startup Repair tidak berhasil, opsi lain di menu recovery adalah System Restore (mengembalikan sistem ke titik restore sebelumnya), Reset This PC (install ulang Windows dengan/tanpa menghapus data), atau Command Prompt untuk perbaikan manual. Jika semua opsi gagal dan Windows tetap tidak bisa booting, kemungkinan perlu install ulang Windows atau ada masalah hardware (hard disk rusak), hubungi teknisi IT.', 'windows,troubleshooting,booting,startup repair,automatic repair', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(422, 'Troubleshooting Login Windows Gagal', 'Jika tidak bisa login ke Windows atau password ditolak, lakukan langkah berikut: Pada layar login Windows, pilih akun pengguna yang tersedia dan sesuai dengan akun yang akan digunakan, perhatikan nama akun dengan teliti karena mungkin ada beberapa akun dengan nama mirip. Masukkan kata sandi (password) dengan benar pada kolom password yang disediakan, ketik dengan hati-hati karena password bersifat case-sensitive (membedakan huruf besar dan kecil). Perhatikan penggunaan huruf besar (uppercase) dan huruf kecil (lowercase) pada keyboard saat mengetik password, pastikan sesuai dengan password asli yang telah didaftarkan. Periksa dan pastikan tombol Caps Lock pada keyboard tidak aktif (lampu indikator Caps Lock mati) saat mengetik password, karena jika Caps Lock aktif maka semua huruf akan menjadi huruf besar dan password akan salah. Perhatikan juga Num Lock jika password mengandung angka dari numpad. Tekan tombol Enter pada keyboard atau klik tombol \"Sign In\" untuk melanjutkan proses login ke sistem Windows. Jika password masih ditolak dengan pesan \"The password is incorrect\", periksa kembali apakah password yang diketik benar-benar sesuai. Jika yakin password benar namun tetap tidak bisa login, kemungkinan akun terkunci (locked) setelah beberapa kali salah password. Jika lupa password sama sekali atau mengalami kendala login yang tidak dapat diatasi sendiri, segera hubungi administrator sistem, helpdesk IT, atau petugas IT yang bertugas untuk mendapatkan bantuan reset password, unlock akun, atau recovery akun.', 'windows,troubleshooting,login,password,sign in', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(423, 'Troubleshooting Keyboard Mouse Tidak Berfungsi', 'Jika keyboard atau mouse tidak berfungsi atau tidak terdeteksi di PC Windows, lakukan troubleshooting berikut: Cabut kabel USB keyboard atau mouse dari port USB yang sedang digunakan dengan hati-hati, tunggu beberapa detik (3-5 detik) untuk memberi waktu sistem melepas driver. Pasang kembali kabel keyboard atau mouse ke port USB yang tersedia, bisa di port yang sama atau coba port USB lain yang berbeda di bagian depan atau belakang CPU untuk memastikan port tidak bermasalah. Tunggu beberapa saat hingga perangkat terdeteksi oleh sistem Windows yang biasanya akan muncul notifikasi \"Installing device driver\" atau bunyi notifikasi USB connected. Windows akan secara otomatis menginstall driver yang diperlukan untuk perangkat tersebut. Coba gerakkan mouse atau tekan tombol keyboard untuk menguji apakah sudah berfungsi kembali dengan normal. Jika perangkat masih tidak berfungsi setelah cabut-pasang ulang, restart komputer dengan menekan tombol power CPU atau menggunakan keyboard lain jika ada. Setelah restart, tunggu Windows boot sempurna dan masuk desktop, kemudian cek kembali apakah keyboard dan mouse sudah berfungsi. Pastikan perangkat dapat digunakan kembali untuk mengetik atau menggerakkan kursor dengan lancar. Jika masih tidak berfungsi, kemungkinan keyboard/mouse rusak (bukan masalah port/sistem), coba gunakan perangkat tersebut di komputer lain untuk memastikan. Bisa juga masalah driver, coba update driver di Device Manager atau gunakan keyboard/mouse berbeda.', 'windows,troubleshooting,keyboard,mouse,usb', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(424, 'Troubleshooting PC Windows Lambat', 'Jika komputer PC Windows berjalan lambat, lemot, atau lag, lakukan optimasi berikut: Pertama, tutup aplikasi atau program yang tidak digunakan atau sedang idle untuk membebaskan resource sistem seperti RAM dan CPU. Tekan kombinasi tombol Ctrl + Shift + Esc secara bersamaan pada keyboard untuk membuka Task Manager dengan cepat. Di Task Manager, lihat tab \"Processes\" yang menampilkan semua aplikasi dan proses yang sedang berjalan beserta penggunaan CPU, Memory (RAM), Disk, dan Network-nya. Identifikasi aplikasi yang memakan resource besar (penggunaan CPU atau Memory tinggi di atas 50-70%) namun tidak sedang digunakan atau tidak penting. Klik pada aplikasi atau proses tersebut untuk memilihnya, lalu klik tombol \"End Task\" di bagian bawah kanan Task Manager untuk menghentikan proses aplikasi yang tidak diperlukan dan membebaskan resource. Lakukan hal ini untuk beberapa aplikasi yang memakan resource besar. Setelah menutup aplikasi yang tidak perlu, tutup Task Manager dan lakukan restart komputer dengan cara yang benar (Start > Power > Restart) untuk me-refresh seluruh sistem, membersihkan RAM, dan memuat ulang semua service Windows dari awal. Setelah restart selesai dan komputer masuk ke desktop, tunggu beberapa menit hingga sistem stabil dan semua startup service selesai loading. Gunakan kembali komputer dan perhatikan apakah performa sudah membaik. Untuk optimasi lebih lanjut, bersihkan disk dengan Disk Cleanup, disable startup programs yang tidak perlu di Task Manager tab Startup, scan malware dengan Windows Defender, atau upgrade RAM jika konsisten lambat.', 'windows,troubleshooting,lambat,lag,task manager,performa', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(425, 'Troubleshooting Tidak Ada Suara Windows', 'Jika PC Windows tidak ada suara atau audio tidak keluar, lakukan troubleshooting berikut: Pertama, periksa volume pada sistem Windows dengan mengklik ikon speaker di system tray pojok kanan bawah layar. Pastikan volume tidak dalam posisi 0% atau terlalu rendah, naikkan volume dengan slider ke level 50-70% atau sesuai kebutuhan. Pastikan ikon speaker tidak dalam kondisi mute (ikon speaker dengan tanda silang merah), jika mute klik untuk unmute atau tekan tombol mute pada keyboard. Periksa dan pilih perangkat output audio yang sesuai dengan mengklik kanan ikon speaker, pilih \"Open Sound Settings\", lalu di bagian \"Choose your output device\" pastikan perangkat yang dipilih adalah speaker atau headphone yang benar-benar terpasang dan aktif (bukan perangkat yang tidak ada atau disconnect). Windows sering salah memilih output device terutama jika ada banyak perangkat audio. Jika output device sudah benar namun tetap tidak ada suara, klik kanan ikon speaker dan pilih \"Troubleshoot sound problems\" untuk menjalankan Windows audio troubleshooter otomatis. Jika masih tidak ada suara, coba restart komputer untuk me-refresh audio driver dan service audio Windows. Setelah restart dan masuk ke desktop, tunggu beberapa saat hingga sistem stable, lalu cek kembali suara dengan memutar video atau audio untuk memastikan speaker sudah berfungsi normal. Jika masih bermasalah, kemungkinan driver audio perlu diupdate di Device Manager, atau speaker/headphone rusak, coba di perangkat lain untuk memastikan.', 'windows,troubleshooting,suara,audio,speaker,mute', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(426, 'Troubleshooting Internet Tidak Terhubung Windows', 'Jika koneksi internet PC Windows tidak terhubung atau tidak bisa connect, lakukan troubleshooting berikut: Periksa kabel LAN (Ethernet) apakah sudah terpasang dengan benar dan kuat ke port LAN di CPU dan ke router/switch, pastikan tidak ada kabel yang longgar atau terlepas. Jika menggunakan koneksi WiFi, periksa koneksi WiFi dengan mengklik ikon network di system tray, pastikan WiFi dalam kondisi ON (enabled) dan terhubung ke jaringan yang benar (SSID yang sesuai seperti Tel-U Connect). Jika status menunjukkan \"No Internet\" atau \"Limited\", kemungkinan ada masalah autentikasi atau DHCP. Klik icon network dan pilih \"Network & Internet Settings\", pastikan adapter network (WiFi atau Ethernet) dalam kondisi enabled dan tidak disabled. Pastikan koneksi jaringan aktif dengan melihat status connection apakah \"Connected\" dengan akses internet. Jika status \"Not Connected\" atau ada tanda warning, coba disconnect dan connect ulang ke jaringan WiFi dengan memasukkan password ulang. Untuk troubleshooting lebih lanjut, restart komputer dengan cara yang benar (Start > Power > Restart) untuk me-refresh network adapter dan network stack Windows. Setelah restart, tunggu hingga Windows boot sempurna dan masuk desktop, biarkan beberapa saat (30-60 detik) untuk sistem network services aktif penuh. Tunggu hingga jaringan terhubung kembali secara otomatis atau manual connect ulang jika diperlukan. Setelah status network menunjukkan \"Connected\" dengan icon internet normal, coba buka browser dan akses website untuk test koneksi. Gunakan internet kembali setelah koneksi stabil. Jika masih tidak bisa connect, kemungkinan masalah di router, ISP, atau network card, coba flush DNS (ipconfig /flushdns), reset network adapter, atau hubungi IT support.', 'windows,troubleshooting,internet,wifi,lan,tidak terhubung', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(427, 'Perawatan PC Windows', 'Untuk merawat PC Windows agar tetap optimal dan awet, lakukan perawatan berikut: Pastikan ruang penyimpanan (storage) di hard disk atau SSD masih mencukupi dengan menyisakan minimal 10-20% space kosong dari total kapasitas. Disk yang penuh dapat membuat sistem lambat dan tidak stabil. Gunakan Disk Cleanup atau uninstall program yang tidak terpakai untuk mengosongkan space. Hindari membuka banyak aplikasi berat secara bersamaan karena dapat membebani RAM dan CPU, menyebabkan komputer lag atau freeze. Tutup aplikasi yang tidak digunakan untuk membebaskan resource. Simpan dan backup data penting secara berkala ke external hard disk, cloud storage (Google Drive, OneDrive), atau media penyimpanan lain untuk menghindari kehilangan data akibat kerusakan hardware atau virus. Jaga kebersihan ventilasi atau lubang udara CPU dari debu dengan membersihkan secara berkala (3-6 bulan sekali) menggunakan vacuum cleaner, blower, atau compressed air. Debu yang menumpuk dapat menyumbat sirkulasi udara, menyebabkan komponen overheat, dan memperpendek umur hardware. Pastikan ventilasi tidak terhalang benda. Lakukan pembaruan sistem Windows (Windows Update) secara berkala jika diperlukan untuk mendapatkan patch keamanan terbaru, bug fixes, dan peningkatan performa. Namun, di lingkungan lab atau institusi, Windows Update mungkin dikelola oleh admin IT, jadi koordinasikan dengan IT support. Scan malware secara rutin dengan Windows Defender atau antivirus. Jangan install software sembarangan dari sumber tidak terpercaya. Matikan komputer dengan benar menggunakan Shut Down, jangan cabut listrik secara paksa.', 'windows,perawatan,maintenance,optimasi', 'general', 0, NULL, '2026-02-05 10:18:08', '2026-02-05 03:18:08'),
(428, 'Apple iMac Lab Multimedia', 'Apple iMac di Lab Multimedia adalah komputer desktop produksi Apple Inc dengan sistem operasi MacOS yang digunakan untuk mengolah data, menjalankan aplikasi multimedia, dan menunjang aktivitas kerja kreatif. iMac dilengkapi dengan Kamera HD FaceTime 1080p dan Mikrofon untuk panggilan video dan perekaman, Layar Retina 5K dengan resolusi tinggi untuk tampilan gambar tajam dan warna akurat, serta Speaker berkualitas untuk keluaran audio. Di bagian belakang terdapat Port USB Type-A untuk perangkat tambahan, Port Thunderbolt 2 untuk transfer data berkecepatan tinggi, Port Ethernet (LAN) untuk koneksi jaringan stabil, Port Daya untuk pasokan listrik, dan Tombol Power untuk menyalakan/mematikan komputer. Cara penggunaan: hubungkan kabel daya dengan benar, tekan tombol Power di belakang iMac, pilih akun Kuliah saat login, masukkan password jika diminta. Untuk koneksi internet, klik ikon WiFi di pojok kanan atas dan pilih Tel-U Connect. Untuk menjalankan aplikasi, klik Launchpad dan pilih aplikasi yang diinginkan.', 'imac,apple,macos,lab multimedia,komputer desktop', 'general', 0, NULL, '2026-02-05 10:18:50', '2026-02-05 03:18:50'),
(429, 'Troubleshooting iMac Lab Multimedia', 'Troubleshooting untuk iMac di Lab Multimedia: Jika iMac tidak menyala, periksa kabel daya apakah terhubung dengan benar ke sumber listrik, pastikan sumber listrik aktif, dan tekan tombol Power di belakang iMac selama beberapa detik. Jika tidak bisa login, pastikan username dan password dimasukkan dengan benar sesuai akun yang diberikan, periksa tombol Caps Lock tidak aktif saat mengetik password, jika lupa password hubungi administrator atau petugas IT. Jika tidak bisa terhubung ke internet, pastikan WiFi aktif dan ikon jaringan terlihat di menu bar, pilih ulang jaringan Tel-U Connect, masukkan kembali username dan password dengan benar, jika gagal lakukan restart iMac dan coba sambungkan kembali. Jika aplikasi tidak bisa dibuka, tutup aplikasi yang bermasalah lalu buka kembali, restart iMac untuk menyegarkan sistem, pastikan aplikasi sudah terinstal dengan benar. Perawatan: gunakan iMac di ruangan bersih dan kering dengan sirkulasi udara baik, jangan mematikan komputer secara paksa, matikan dengan prosedur yang benar setelah selesai digunakan.', 'imac,troubleshooting,lab multimedia', 'general', 0, NULL, '2026-02-05 10:18:50', '2026-02-05 03:18:50'),
(430, 'Apple Wireless Keyboard', 'Apple Wireless Keyboard adalah keyboard nirkabel produksi Apple Inc yang berfungsi sebagai perangkat input untuk mengetik dan mengontrol komputer atau perangkat lain melalui koneksi Bluetooth. Keyboard ini memiliki Power On Light (Lampu Indikator Daya) yang menunjukkan status daya keyboard: lampu menyala berarti keyboard aktif/terhubung, lampu berkedip berarti keyboard sedang mencari koneksi (pairing mode), lampu mati berarti keyboard nonaktif atau kehabisan baterai. On/Off Switch (Tombol Daya) untuk menyalakan dan mematikan keyboard guna menghemat baterai, geser ke ON untuk mengaktifkan dan OFF untuk mematikan. Keyboard dilengkapi dengan berbagai tombol fungsi: Esc untuk membatalkan perintah, F1-F2 untuk mengatur brightness layar, F3 untuk Mission Control, F4 untuk Launchpad, F5-F6 untuk keyboard brightness (jika ada backlight), F7-F9 untuk kontrol media (rewind, play/pause, fast forward), F10-F12 untuk kontrol volume (mute, volume down, volume up), dan tombol Power/Eject untuk sleep, restart, atau shutdown Mac. Keyboard menggunakan baterai yang dimasukkan ke kompartemen baterai di bagian bawah atau samping keyboard sesuai polaritas yang benar.', 'apple,wireless keyboard,bluetooth,keyboard', 'general', 0, NULL, '2026-02-05 10:18:50', '2026-02-05 03:18:50'),
(431, 'Menghubungkan Apple Wireless Keyboard', 'Untuk menghubungkan Apple Wireless Keyboard ke komputer, ikuti langkah berikut: Pertama, buka kompartemen baterai di bagian bawah atau samping keyboard dengan memutar atau menggeser penutup kompartemen. Masukkan baterai (biasanya 2-3 buah baterai AA) ke dalam kompartemen sesuai dengan polaritas (+/-) yang tertera di dalam kompartemen, pastikan baterai terpasang dengan benar dan kuat. Tutup kembali penutup kompartemen baterai hingga terkunci. Geser tombol On/Off yang terletak di sisi atau bagian belakang keyboard ke posisi ON hingga lampu indikator LED menyala, yang menandakan keyboard telah aktif dan mulai mencari koneksi Bluetooth (lampu akan berkedip saat pairing mode). Pada komputer Mac atau PC, aktifkan Bluetooth dengan membuka System Settings/Preferences > Bluetooth atau klik icon Bluetooth di menu bar. Pastikan Bluetooth dalam kondisi ON dan sedang mencari perangkat. Dari daftar perangkat Bluetooth yang muncul, cari dan pilih \"Apple Wireless Keyboard\" atau nama keyboard yang terdeteksi. Klik tombol \"Pair\" atau \"Connect\" untuk menghubungkan. Sistem mungkin meminta untuk mengetik kode PIN yang muncul di layar pada keyboard sebagai verifikasi pairing. Ketik kode tersebut dan tekan Enter. Tunggu beberapa detik hingga keyboard berhasil terhubung (paired) dengan komputer, lampu indikator akan menyala stabil atau mati setelah connected. Setelah terhubung, keyboard siap digunakan untuk mengetik dan memberikan input ke komputer secara wireless tanpa kabel.', 'apple,wireless keyboard,pairing,bluetooth,koneksi', 'general', 0, NULL, '2026-02-05 10:18:50', '2026-02-05 03:18:50'),
(432, 'Troubleshooting Apple Wireless Keyboard', 'Troubleshooting untuk Apple Wireless Keyboard: Jika keyboard tidak menyala, pastikan baterai terpasang dengan benar sesuai polaritas (+/-), periksa kondisi baterai dengan battery tester atau ganti dengan baterai baru jika habis atau lemah, geser tombol On/Off ke posisi ON hingga lampu indikator menyala. Jika keyboard tidak terdeteksi oleh komputer, pastikan Bluetooth komputer dalam kondisi aktif (ON) dan tidak dalam airplane mode, dekatkan keyboard ke komputer dengan jarak maksimal 10 meter agar sinyal Bluetooth lebih kuat dan stabil, lepas dan pasang kembali baterai keyboard untuk reset koneksi, coba putuskan (unpair) perangkat Bluetooth lain yang terhubung sementara waktu untuk mengurangi interferensi, kemudian coba pair ulang keyboard. Jika lampu indikator berkedip terus dan tidak terkoneksi, matikan keyboard dengan menggeser tombol Off, tunggu beberapa detik (5-10 detik), lalu nyalakan kembali dengan menggeser tombol On, hapus \"Apple Wireless Keyboard\" dari daftar perangkat Bluetooth di komputer dengan mengklik Forget/Remove Device, lalu lakukan pairing ulang dari awal dengan mengikuti prosedur koneksi, restart komputer jika masalah masih terjadi untuk me-refresh Bluetooth stack. Jika tombol keyboard tidak berfungsi atau tidak merespons saat ditekan, pastikan baterai masih cukup daya dengan mengecek indikator atau mengganti baterai baru, periksa apakah keyboard sudah benar-benar terhubung ke komputer dengan status \"Connected\" di Bluetooth settings, coba matikan dan nyalakan kembali keyboard untuk refresh koneksi, coba tekan tombol yang berbeda untuk memastikan bukan masalah mekanis tombol tertentu. Perawatan: matikan keyboard jika tidak digunakan dalam waktu lama untuk menghemat baterai, ganti baterai secara berkala jika daya mulai melemah atau keyboard sering disconnect, hindari paparan cairan seperti air atau kopi yang dapat merusak komponen elektronik, hindari debu berlebih dengan menutup keyboard saat tidak digunakan, hindari benturan keras yang dapat merusak tombol atau PCB internal.', 'apple,wireless keyboard,troubleshooting,bluetooth', 'general', 0, NULL, '2026-02-05 10:18:50', '2026-02-05 03:18:50'),
(433, 'Wireless Mouse Rechargeable', 'Wireless Mouse Rechargeable adalah perangkat input nirkabel yang diproduksi oleh berbagai pabrikan seperti Logitech, Apple, Xiaomi, Lenovo, dan lain-lain. Mouse ini berfungsi untuk menggerakkan kursor, melakukan klik, dan navigasi pada komputer tanpa kabel menggunakan baterai tanam isi ulang (rechargeable Lithium-ion battery) seperti baterai pada iPhone atau smartphone modern, bukan baterai AA/AAA yang sekali pakai. Keunggulan baterai Lithium-ion adalah daya tahan lama, dapat diisi ulang berkali-kali, praktis tanpa perlu beli baterai baru, ukuran ringkas sehingga mendukung desain mouse yang lebih tipis dan ringan. Mouse memiliki tiga bagian utama: Tombol Kiri (Left Click) sebagai klik utama untuk memilih, membuka, dan mengeksekusi file atau perintah, Tombol Kanan (Right Click) untuk menampilkan menu konteks atau opsi tambahan, dan Scroll Wheel di tengah untuk menggulir halaman ke atas dan ke bawah serta dapat diklik sebagai middle click untuk navigasi cepat. Mouse terhubung ke komputer melalui koneksi Bluetooth wireless atau menggunakan USB receiver dongle kecil yang ditancapkan ke port USB komputer. Baterai Lithium-ion yang tertanam di dalam mouse tidak dapat dilepas oleh pengguna dan harus diisi ulang menggunakan kabel USB (Micro USB, USB-C, atau Lightning tergantung model) yang disambungkan ke port charging di mouse.', 'wireless mouse,rechargeable,bluetooth,lithium-ion', 'general', 0, NULL, '2026-02-05 10:19:07', '2026-02-05 03:19:07'),
(434, 'Cara Menggunakan Wireless Mouse Rechargeable', 'Untuk menggunakan Wireless Mouse Rechargeable, ikuti langkah berikut: Pertama, pastikan baterai mouse terisi dengan cara mengisi daya mouse menggunakan kabel charging yang disertakan (Micro USB, USB-C, atau Lightning sesuai model mouse). Colokkan ujung kabel ke port charging mouse dan ujung satunya ke port USB komputer, laptop, atau USB charger adaptor. Tunggu hingga indikator LED charging menyala (biasanya merah atau oranye saat charging) yang menandakan proses pengisian berlangsung. Isi daya hingga baterai penuh yang ditandai dengan LED berubah warna menjadi hijau atau mati, biasanya memerlukan waktu 1-3 jam untuk full charge tergantung kapasitas baterai. Setelah baterai penuh, cabut kabel charging dari mouse. Nyalakan mouse dengan menekan atau menggeser tombol power yang biasanya terletak di bagian bawah mouse ke posisi ON hingga LED indikator menyala atau berkedip menandakan mouse aktif. Hubungkan mouse ke komputer melalui dua cara: jika menggunakan USB receiver (wireless dongle), colokkan USB receiver kecil ke port USB komputer dan tunggu hingga terdeteksi otomatis, atau jika menggunakan Bluetooth, aktifkan Bluetooth di komputer dan lakukan pairing dengan mouse dengan mencari device di Bluetooth settings dan klik Pair/Connect. Tunggu beberapa saat hingga mouse terdeteksi dan terhubung dengan komputer, lampu indikator akan stabil atau mati setelah connected. Setelah terhubung, mouse siap digunakan. Gerakkan mouse untuk menggerakkan kursor di layar, klik kiri untuk memilih, klik kanan untuk menu, dan gunakan scroll wheel untuk navigasi halaman.', 'wireless mouse,cara menggunakan,charging,pairing', 'general', 0, NULL, '2026-02-05 10:19:07', '2026-02-05 03:19:07'),
(435, 'Troubleshooting Wireless Mouse Rechargeable', 'Troubleshooting untuk Wireless Mouse Rechargeable: Jika mouse tidak menyala, pastikan mouse sudah diisi daya dengan benar menggunakan kabel charging yang sesuai dan original, periksa indikator LED saat charging apakah menyala (jika tidak menyala mungkin kabel atau port charging bermasalah), tunggu beberapa saat (minimal 15-30 menit) jika baterai habis total karena mouse perlu waktu untuk akumulasi daya awal sebelum bisa menyala, tekan atau geser tombol power ke posisi ON hingga LED indikator mouse menyala menandakan mouse aktif. Jika mouse tidak terdeteksi oleh komputer atau koneksi terputus, pastikan mouse dalam keadaan menyala dengan mengecek LED indikator atau coba tekan tombol untuk memastikan power on, periksa koneksi Bluetooth di komputer apakah aktif (ON) dan tidak dalam airplane mode dengan membuka Bluetooth settings, jika menggunakan USB receiver pastikan dongle terpasang dengan benar di port USB dan tidak longgar, coba port USB lain jika perlu, dekatkan mouse ke komputer atau USB receiver dengan jarak maksimal 10 meter agar sinyal wireless lebih kuat karena jarak jauh dapat menyebabkan koneksi tidak stabil, putuskan atau disconnect perangkat Bluetooth lain yang terhubung sementara waktu untuk mengurangi interferensi sinyal, kemudian coba reconnect mouse, jika menggunakan Bluetooth coba unpair/forget device dan lakukan pairing ulang dari awal. Jika kursor tidak bergerak, bergerak lambat, atau respons mouse delay, periksa apakah baterai mouse masih cukup daya dengan mengecek LED indikator atau level baterai di system settings, isi ulang baterai jika sudah low karena baterai lemah dapat menyebabkan performa menurun, coba matikan mouse dengan menekan tombol power Off, tunggu 5-10 detik, lalu nyalakan kembali mouse dengan menekan tombol On untuk refresh koneksi dan sensor, pastikan permukaan meja atau mousepad sesuai untuk sensor optik mouse, hindari permukaan kaca, cermin, atau terlalu mengkilap karena sensor tidak dapat tracking dengan baik, gunakan mousepad dengan tekstur yang baik untuk tracking optimal, bersihkan sensor optik di bagian bawah mouse dari debu atau kotoran menggunakan cotton bud atau kain lembut, restart komputer jika diperlukan untuk refresh driver mouse. Perawatan: isi ulang baterai mouse secara berkala sebelum benar-benar habis (jangan tunggu 0%) untuk menjaga kesehatan baterai Lithium-ion dan umur baterai lebih panjang, usahakan charge saat battery level 20-30% dan jangan overcharge terlalu lama setelah penuh, gunakan kabel pengisi daya yang sesuai dan original dari pabrikan atau kabel berkualitas baik untuk menghindari kerusakan baterai atau port charging, hindari charger dengan voltage terlalu tinggi, matikan mouse jika tidak digunakan dalam waktu lama (lebih dari 1-2 hari) untuk menghemat daya baterai dan mencegah battery drain, hindari paparan panas berlebih seperti meninggalkan mouse di bawah sinar matahari langsung atau dekat sumber panas karena dapat merusak baterai Lithium-ion, hindari benturan keras yang dapat merusak komponen internal atau baterai, jauhkan dari cairan atau air yang dapat merusak elektronik, bersihkan permukaan mouse secara berkala dengan kain lembut.', 'wireless mouse,troubleshooting,charging,koneksi,baterai', 'general', 0, NULL, '2026-02-05 10:19:07', '2026-02-05 03:19:07'),
(436, 'bang fahri?', 'fahri adalah salah satu pengembang website Mesin Learning FIK', 'bang, fahri?', 'general', 0, NULL, '2026-02-05 08:37:51', '2026-02-05 01:37:51'),
