(285, 'lab fotografi ada dimana?', 'Lab Fotografi ada di Lantai 5 Ada dua lab fotografi yang hitam dan yang putih Yang hitam (low key) ruang IK1.05.10 Yang putih (high key) ruang IK1.05.11 Masing-masing studio terdapat dua lampu studio dan terdapat background juga Jam operasional Lab Studio dari jam 08.30 - 16.30 hari sabtu dan minggu libur', 'Ignored', '2025-07-25 07:18:26', 0, NULL, NULL, NULL),
(286, 'jam operasional lab fotografi', 'Lab Fotografi ada di Lantai 5 Ada dua lab fotografi yang hitam dan yang putih Yang hitam (low key) ruang IK1.05.10 Yang putih (high key) ruang IK1.05.11 Masing-masing studio terdapat dua lampu studio dan terdapat background juga Jam operasional Lab Studio dari jam 08.30 - 16.30 hari sabtu dan minggu libur Terdapat 4 (empat) Lab di lantai 5 ada Lab Audio, Lab Video dan 2 (dua) Lab Fotografi. Jam operasional Lab sesuai dengan jam kerja mulai dari jam 08.30-16.30 untuk hari Sabtu dan Minggu Libur.', 'Ignored', '2025-07-25 07:18:58', 0, NULL, NULL, NULL),
(287, 'awdasd', 'kamu mencari *awdasd* pada Human Resource and Finance, namun saya tidak dapat bisa menjawab hal tersebut.', 'Ignored', '2025-07-25 07:59:17', 0, NULL, NULL, NULL),
