(300, 'fik itu apa', 'FIK adalah kepanjangan dari Fakultas Industri Kreatif merupakan salah satu Fakultas yang ada di Universitas Telkom.', 'Ignored', '2025-07-30 01:33:43', 0, NULL, NULL, NULL),
(301, 'ada berapa prodi di fik', 'kamu mencari *ada berapa prodi di fik* pada Laboratory, namun saya tidak dapat bisa menjawab hal tersebut.', 'Ignored', '2025-07-30 01:34:08', 0, NULL, NULL, NULL),
